INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280f3e3c98b0941765e35', '不错一直住花园酒店', '["https://dimg04.c-ctrip.com/images/0231c12000b6ke2hk229B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-08', '城央绿意大床房', '大床房', '情侣出游', 9, 2.302585092994046, 0, 0.0, 1, 0.6931471805599453, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '不错一直住花园酒店', '不错一直住花园酒店', '2023-05-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680280fee3c98b0941765e36', '常被亲友问为啥每次到广州 花园酒店都是首选？我觉得虽然建成多年 但这里仍然是卓越的经典酒店代表 室内设施维护的极佳-至今大堂和花园都是熠熠生辉的存在！这里服务多年以来也是保持优秀，从门童到礼宾客房都彬彬有礼，即便北上深住惯国际品牌酒店比较下也会对花园的水准折服；前台接待是酒店的灵魂人物，这次接待的Yedda令人印象深刻！看到我们家庭入住就主动找出我的会员号，给予升级服务，家人很惊喜，更加固花园粉丝地位！酒店拥有米其林两星的泰安门，以及经典茶楼荔湾亭，加之市中心淘金的地段也是餐厅咖啡密布，粤菜黄埔军校利苑就在旁边，试问如今哪家国际品牌在广州能拥有如此丰富的经典配套资源！', '["https://dimg04.c-ctrip.com/images/0236v12000agtma3p0F78_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-18', '花园双床房', '双床房', '其他', 287, 5.662960480135946, 0, 0.0, 9, 2.302585092994046, 9, '["整体满意度", "前台服务", "周边配套"]'::jsonb, '整体满意度', '前台服务', '周边配套', '未知酒店', '未知地点', '匿名', '常被亲友问为啥每次到广州 花园酒店都是首选？我觉得虽然建成多年 但这里仍然是卓越', '常被亲友问为啥每次到广州 花园酒店都是首选？我觉得虽然建成多年 但这里仍然是卓越的经典酒店代表 室内设施维护的极佳-至今大堂和花园都是熠熠生辉的存在！这里服务多年以来也是保持优秀，从门童到礼宾客房都彬彬有礼，即便北上深住惯国际品牌酒店比较下也会对花园的水准折服；前台接待是酒店的灵魂人物，这次接待的Yedda令人印象深刻！看到我们家庭入住就主动找出我的会员号，给予升级服务，家人很惊喜，更加固花园粉丝地位！酒店拥有米其林两星的泰安门，以及经典茶楼荔湾亭，加之市中心淘金的地段也是餐厅咖啡密布，粤菜黄埔军校利苑就在旁边，试问如今哪家国际品牌在广州能拥有如此丰富的经典配套资源！', '2023-01-18', 5, '整体满意度');
