INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e42', '客房很舒服，酒店环境真的很喜欢，酒店前台viria很热情贴心。', '["https://dimg04.c-ctrip.com/images/0236g12000c3q5aoyEDA3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232u12000c3q9wioAD0D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000c3qd2s222BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '红棉大床套房', '套房', '情侣出游', 31, 3.4657359027997265, 0, 0.0, 22, 3.1354942159291497, 5, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '客房很舒服，酒店环境真的很喜欢，酒店前台viria很热情贴心。', '客房很舒服，酒店环境真的很喜欢，酒店前台viria很热情贴心。', '2023-09-10', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e43', '来过广州很多次了，但花园酒店还是第一次入住，尽管对老广来说这个酒店已经一点都不陌生，但对于外地人来讲，真的是一次非常好的打卡体验。
浓重的历史氛围，里面的酒店博物馆都给人非常好的体验，然后让人了解到这所酒店在历史当中所经历的人与酒店准备的东西，除了常见五星级酒店都会准备的咖啡机饮品以外，甚至还有一次性的搓澡巾海盐，真的是非常的细心。
服务方面特别感谢前台的betty小姐在入住的时候给我们做了一个房间的升级，再加上中秋节的月饼，真的是氛围满满。', '["https://dimg04.c-ctrip.com/images/0230q12000cb8zs7a8F56_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236i12000cb9b8ar6AED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000cb98f7k07F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000cb9b84yC7EB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000cb93m0eDFC0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-02', '花园大床房', '大床房', '情侣出游', 223, 5.41164605185504, 0, 0.0, 6, 1.9459101490553128, 9, '["整体满意度", "前台服务", "房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '来过广州很多次了，但花园酒店还是第一次入住，尽管对老广来说这个酒店已经一点都不陌', '来过广州很多次了，但花园酒店还是第一次入住，尽管对老广来说这个酒店已经一点都不陌生，但对于外地人来讲，真的是一次非常好的打卡体验。
浓重的历史氛围，里面的酒店博物馆都给人非常好的体验，然后让人了解到这所酒店在历史当中所经历的人与酒店准备的东西，除了常见五星级酒店都会准备的咖啡机饮品以外，甚至还有一次性的搓澡巾海盐，真的是非常的细心。
服务方面特别感谢前台的betty小姐在入住的时候给我们做了一个房间的升级，再加上中秋节的月饼，真的是氛围满满。', '2023-10-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e44', '这次十一广州之行的最后一晚选在了广州花园酒店，之前住过白云宾馆，花园酒店和白云宾馆隔了条马路，酒店门口就是地铁淘金站，对面有广州友谊商场，周边老字号餐饮齐全，广州酒家，陶陶居，点都德步行几分钟就到。打车出租司机说我们选的花园酒店服务特别好，软硬件设施在广州都是非常好的！办理入住时确实感受到了，前台接待ARIEL和kamille两位小姑娘看到我儿子手臂受伤，主动帮助我们，送了我们迎宾鲜花，还送了酒店纪念品，帮我们升级了房间！让我们切身感受到了酒店好客之礼！谢谢花园酒店为这次旅行挂上完美句号！', '["https://dimg04.c-ctrip.com/images/0230i12000cccv0ka4E5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232512000ccctgax737C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000cccwkp2BA90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236q12000ccct1mcCCF8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000cccteelA5CA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-06', '花园双床房', '双床房', '家庭亲子', 247, 5.513428746164983, 0, 0.0, 24, 3.218875824868201, 9, '["前台服务", "交通便利性", "周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套', '未知酒店', '未知地点', '匿名', '这次十一广州之行的最后一晚选在了广州花园酒店，之前住过白云宾馆，花园酒店和白云宾', '这次十一广州之行的最后一晚选在了广州花园酒店，之前住过白云宾馆，花园酒店和白云宾馆隔了条马路，酒店门口就是地铁淘金站，对面有广州友谊商场，周边老字号餐饮齐全，广州酒家，陶陶居，点都德步行几分钟就到。打车出租司机说我们选的花园酒店服务特别好，软硬件设施在广州都是非常好的！办理入住时确实感受到了，前台接待ARIEL和kamille两位小姑娘看到我儿子手臂受伤，主动帮助我们，送了我们迎宾鲜花，还送了酒店纪念品，帮我们升级了房间！让我们切身感受到了酒店好客之礼！谢谢花园酒店为这次旅行挂上完美句号！', '2023-10-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e46', '广州花园酒店，老牌五星级酒店，位置老城区，但出行很方便，性价比非常好，酒店气派、设施齐全，符合五星级标准', '["https://dimg04.c-ctrip.com/images/0232212000ajm0gt9E8B7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000ajm3ym4BAD4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000ajlwv24904F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-31', '花园大床房', '大床房', '家庭亲子', 52, 3.970291913552122, 0, 0.0, 8, 2.19722457733622, 7, '["性价比", "交通便利性", "整体满意度"]'::jsonb, '性价比', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '广州花园酒店，老牌五星级酒店，位置老城区，但出行很方便，性价比非常好，酒店气派、', '广州花园酒店，老牌五星级酒店，位置老城区，但出行很方便，性价比非常好，酒店气派、设施齐全，符合五星级标准', '2023-01-31', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e47', '酒店很大气，进大堂就闻到很香的味道，工作人员也很热情，服务很好，距离地铁站近，出行方便；值得入住，推荐', '["https://dimg04.c-ctrip.com/images/0234112000akbkwpj0081_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000akb5uxv3388_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237012000akbfvg0A5FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235c12000akbmull4634_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235u12000akbm0pt6DD5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-02', '花园大床房', '大床房', '家庭亲子', 51, 3.951243718581428, 0, 0.0, 7, 2.079441541679836, 6, '["整体满意度", "前台服务", "交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性', '未知酒店', '未知地点', '匿名', '酒店很大气，进大堂就闻到很香的味道，工作人员也很热情，服务很好，距离地铁站近，出', '酒店很大气，进大堂就闻到很香的味道，工作人员也很热情，服务很好，距离地铁站近，出行方便；值得入住，推荐', '2023-02-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e48', '首先用一个字形容广州花园酒店，那就是“赞”！要点名感谢接待我们的阮小姐Carey！在住店的3晚里面，全程帮我们解决了各种问题，提前帮我们安排了房间，主动帮我们推荐了各种合适的用餐方案，还有小礼物和小食！酒店的环境也让我们一行人印象深刻，一进门的白金五星牌子，check in的巨大金色背景墙，巨大的瀑布和锦鲤花园，甚至大堂里开满花的的桃树都是活的，环境真的就是和它的名字一样，是个到处充满美景的大花园！酒店到处都是给你打招呼的服务员，各种问题都可以得到第一时间的解答，而且非常有耐心。酒店门口因为是春节，还有各种表演和活动，有各种小礼物赠送！我们住的房间还可以看到酒店瀑布、酒店泳池，甚至还有远处的广州塔！我们的酒店早餐有3个餐厅可以用餐，选择了行政酒廊和荔湾亭，早餐都是广式茶点、特色面和粥，还有各种饮料和小食，口味和环境也是没话说，行政酒廊边吃还可以边喂锦鲤、看瀑布美景，真的是非常惬意！这次的春节旅行让我非常满意，广州花园酒店下次一定是我去广州的第一选择！谢谢Carey阮小姐、谢谢广州花园酒店！', '["https://dimg04.c-ctrip.com/images/0236112000aie77ij7681_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230b12000aiea5gp885F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000aiebo5t41C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000aieboz6C033_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000aiea58m91AD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233j12000aieboz7B617_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000aiebcvbDF9D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000aiebn7z0911_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000aiebn1595D5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-26', '花园大床房', '大床房', '家庭亲子', 451, 6.113682179832232, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '首先用一个字形容广州花园酒店，那就是“赞”！要点名感谢接待我们的阮小姐Carey', '首先用一个字形容广州花园酒店，那就是“赞”！要点名感谢接待我们的阮小姐Carey！在住店的3晚里面，全程帮我们解决了各种问题，提前帮我们安排了房间，主动帮我们推荐了各种合适的用餐方案，还有小礼物和小食！酒店的环境也让我们一行人印象深刻，一进门的白金五星牌子，check in的巨大金色背景墙，巨大的瀑布和锦鲤花园，甚至大堂里开满花的的桃树都是活的，环境真的就是和它的名字一样，是个到处充满美景的大花园！酒店到处都是给你打招呼的服务员，各种问题都可以得到第一时间的解答，而且非常有耐心。酒店门口因为是春节，还有各种表演和活动，有各种小礼物赠送！我们住的房间还可以看到酒店瀑布、酒店泳池，甚至还有远处的广州塔！我们的酒店早餐有3个餐厅可以用餐，选择了行政酒廊和荔湾亭，早餐都是广式茶点、特色面和粥，还有各种饮料和小食，口味和环境也是没话说，行政酒廊边吃还可以边喂锦鲤、看瀑布美景，真的是非常惬意！这次的春节旅行让我非常满意，广州花园酒店下次一定是我去广州的第一选择！谢谢Carey阮小姐、谢谢广州花园酒店！', '2023-01-26', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028109e3c98b0941765e49', '花园酒店作为羊城老牌的五星级酒店，新年期间服务保持一贯的高水准，周到细致热情贴心，老广特色十足，诚意推荐。', '["https://dimg04.c-ctrip.com/images/0236u12000aihbug64EC4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236612000aihcf1q13DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000aihbgjiB025_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-26', '红棉大床套房', '套房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 15, 2.772588722239781, 7, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '花园酒店作为羊城老牌的五星级酒店，新年期间服务保持一贯的高水准，周到细致热情贴心', '花园酒店作为羊城老牌的五星级酒店，新年期间服务保持一贯的高水准，周到细致热情贴心，老广特色十足，诚意推荐。', '2023-01-26', 5, '整体满意度');
