INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802811fe3c98b0941765e5a', '房间干净，维护的很好，前台小邓非常热情，服务态度好，瀑布餐厅的下午茶也很棒，泳池服务很棒，愉快的入住体验，', '["https://dimg04.c-ctrip.com/images/0233i12000evfr3zb3781_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236412000evfo1e789EA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000evfevz97D19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-23', '红棉双床套房', '套房', '家庭亲子', 53, 3.9889840465642745, 0, 0.0, 4, 1.6094379124341005, 7, '["卫生状况", "前台服务", "整体满意度"]'::jsonb, '卫生状况', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '房间干净，维护的很好，前台小邓非常热情，服务态度好，瀑布餐厅的下午茶也很棒，泳池', '房间干净，维护的很好，前台小邓非常热情，服务态度好，瀑布餐厅的下午茶也很棒，泳池服务很棒，愉快的入住体验，', '2024-07-23', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802811fe3c98b0941765e5c', '花园酒店是我当年在广州上大学时就与白天鹅并列的五星酒店天花板。三十多年过去了，她依然是广州的酒店顶流！这次入住的粤韵房是新装修的，设施先进，这次还享受了行政酒廊礼遇。春天的花城温暖和煦，酒店花园里鲜花盛开，我们还顺便参观了酒店四楼的“酒店博物馆”，涨了知识，整个入住体验非常好，下次来广州还住花园！顺便表扬行政酒廊帅哥小贺，服务周到、礼貌、儒雅，让人如沐春风！', '["https://dimg04.c-ctrip.com/images/0236t12000aoujj7p9C49_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234812000aouf8h4D3B5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000aouihp76331_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230j12000aoudcwy68B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-19', '红棉大床套房', '套房', '家庭亲子', 180, 5.198497031265826, 0, 0.0, 16, 2.833213344056216, 9, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店是我当年在广州上大学时就与白天鹅并列的五星酒店天花板。三十多年过去了，她', '花园酒店是我当年在广州上大学时就与白天鹅并列的五星酒店天花板。三十多年过去了，她依然是广州的酒店顶流！这次入住的粤韵房是新装修的，设施先进，这次还享受了行政酒廊礼遇。春天的花城温暖和煦，酒店花园里鲜花盛开，我们还顺便参观了酒店四楼的“酒店博物馆”，涨了知识，整个入住体验非常好，下次来广州还住花园！顺便表扬行政酒廊帅哥小贺，服务周到、礼貌、儒雅，让人如沐春风！', '2023-02-19', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802811fe3c98b0941765e5d', '交通方便，地铁出来就是酒店，外观非常气派，大堂布置很特别，吸引打卡。房间卫生干净，岭南特色设计，服务员都热情打招呼，有礼貌，特别是楼层服务员张小燕送了甜点，味道很好。胡主管能详细介绍酒店餐厅和其他设施，给我的入住带来惊喜和方便，性价比高，下次还来！', '["https://dimg04.c-ctrip.com/images/0232m12000c46uxtn5CD8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000c46m5vd1FBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-12', '花园大床房', '大床房', '独自旅行', 124, 4.8283137373023015, 0, 0.0, 3, 1.3862943611198906, 9, '["交通便利性", "卫生状况", "性价比"]'::jsonb, '交通便利性', '卫生状况', '性价比', '未知酒店', '未知地点', '匿名', '交通方便，地铁出来就是酒店，外观非常气派，大堂布置很特别，吸引打卡。房间卫生干净', '交通方便，地铁出来就是酒店，外观非常气派，大堂布置很特别，吸引打卡。房间卫生干净，岭南特色设计，服务员都热情打招呼，有礼貌，特别是楼层服务员张小燕送了甜点，味道很好。胡主管能详细介绍酒店餐厅和其他设施，给我的入住带来惊喜和方便，性价比高，下次还来！', '2023-09-12', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802812be3c98b0941765e5f', '前台热情，免费升级了套房，房间干净卫生，床品很舒服，1楼花园餐厅环境优美，三楼本地特色餐厅值得品尝，广交会期间人很多 但服务依然到位', '["https://dimg04.c-ctrip.com/images/0232h12000g8n54l6D38A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000g8ml8dc7889_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000g8nex4gB60F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000g8nbmxd2966_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-21', '花园双床房', '双床房', '其他', 66, 4.204692619390966, 0, 0.0, 15, 2.772588722239781, 8, '["前台服务", "卫生状况", "餐饮设施"]'::jsonb, '前台服务', '卫生状况', '餐饮设施', '未知酒店', '未知地点', '匿名', '前台热情，免费升级了套房，房间干净卫生，床品很舒服，1楼花园餐厅环境优美，三楼本', '前台热情，免费升级了套房，房间干净卫生，床品很舒服，1楼花园餐厅环境优美，三楼本地特色餐厅值得品尝，广交会期间人很多 但服务依然到位', '2024-10-21', 5, '前台服务');
