INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802812be3c98b0941765e65', '房间质素高，酒店的专属管家小何非常热情，入住时给客人的照顾十分周到，针对旅游客人，还把酒店的所有打卡点都介绍到了，否则客人还不知道花园酒店里就有这么多历史参观点，优秀！
花园酒店显然经过精心设计，除了是个休憩落脚的好去处，本身就包含丰富的历史内涵，从酒店的成立到发展，景观的布置，餐厅的设置，都与广州这个古老的城市文化深度绑定，在广州这么多传统酒店里是非常突出的代表。花园酒店还设置了一个酒店博物馆，讲述酒店在这片土地的变迁发展，更是将广州的近代历程都浓缩一所，非常值得去看看。', '["https://dimg04.c-ctrip.com/images/0234412000ewypiabBC3B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000ewylsceCB77_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000ewykamaF9E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233612000ewyn48008DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-27', '花园大床房', '大床房', '朋友出游', 240, 5.484796933490655, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "整体满意度", "公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施', '未知酒店', '未知地点', '匿名', '房间质素高，酒店的专属管家小何非常热情，入住时给客人的照顾十分周到，针对旅游客人', '房间质素高，酒店的专属管家小何非常热情，入住时给客人的照顾十分周到，针对旅游客人，还把酒店的所有打卡点都介绍到了，否则客人还不知道花园酒店里就有这么多历史参观点，优秀！
花园酒店显然经过精心设计，除了是个休憩落脚的好去处，本身就包含丰富的历史内涵，从酒店的成立到发展，景观的布置，餐厅的设置，都与广州这个古老的城市文化深度绑定，在广州这么多传统酒店里是非常突出的代表。花园酒店还设置了一个酒店博物馆，讲述酒店在这片土地的变迁发展，更是将广州的近代历程都浓缩一所，非常值得去看看。', '2024-07-27', 5, '前台服务');
