INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802813ce3c98b0941765e6b', '老牌酒店值得信赖，入住退房都非常好，房间也不错，春节期间体验感最好的一家酒店。', '["https://dimg04.c-ctrip.com/images/0234g12000ahxda6542A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235w12000ahxd0yoA4DD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230212000ahxd67q9C08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-24', '花园大床房', '大床房', '家庭亲子', 39, 3.688879454113936, 0, 0.0, 9, 2.302585092994046, 5, '["整体满意度", "退房/入住效率", "房间设施"]'::jsonb, '整体满意度', '退房/入住效率', '房间设施', '未知酒店', '未知地点', '匿名', '老牌酒店值得信赖，入住退房都非常好，房间也不错，春节期间体验感最好的一家酒店。', '老牌酒店值得信赖，入住退房都非常好，房间也不错，春节期间体验感最好的一家酒店。', '2023-01-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802813ce3c98b0941765e6c', '从成都旅游回来临时起意来广州花园酒店，晚上到店后，Joe帅哥的服务态度很好，说话很有礼貌，还为我们升级了套房，在这里非常的感谢Joe小哥。
房间的装修很有格调，进门的厕所设计很细节，客人进来房间就不会看到睡觉的地方，办公的小房间还有健身器材确实考虑了作为住店客人的日常生活需要。洗手间很大气，非常喜欢，设计感也很强。明显加装的马桶智能盖板才让我感觉到了酒店的年代感，和洗手台淋浴间一对比，很难想象这是一家1985年开业的酒店，至今内部的装修依旧不过时甚至可以说走到潮流一线。
由于第二天睡过头错过了最爱的酒店早餐，中午去了荔湾亭，虽然有段时间没有来花园酒店的荔湾亭吃饭，但是它的出品依旧在线，非常好评（如果不在意价格的话）。总的来说这次住店体验非常的好，作为广州的招牌之一花园酒店名副其实。最后再次感谢Joe小哥的热情接待。', '["https://dimg04.c-ctrip.com/images/0235v12000akecrnbB281_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000ake7mv9E9C9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000akerny055DA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230s12000ake9336CDEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000akednon66B6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235x12000aket0b946C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000akeapsp3E7A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000akeh3xjBC52_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000akeggv5EEEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-02', '城央绿意大床房', '大床房', '情侣出游', 362, 5.8944028342648505, 0, 0.0, 2, 1.0986122886681098, 9, '["前台服务", "房间设施", "整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度', '未知酒店', '未知地点', '匿名', '从成都旅游回来临时起意来广州花园酒店，晚上到店后，Joe帅哥的服务态度很好，说话', '从成都旅游回来临时起意来广州花园酒店，晚上到店后，Joe帅哥的服务态度很好，说话很有礼貌，还为我们升级了套房，在这里非常的感谢Joe小哥。
房间的装修很有格调，进门的厕所设计很细节，客人进来房间就不会看到睡觉的地方，办公的小房间还有健身器材确实考虑了作为住店客人的日常生活需要。洗手间很大气，非常喜欢，设计感也很强。明显加装的马桶智能盖板才让我感觉到了酒店的年代感，和洗手台淋浴间一对比，很难想象这是一家1985年开业的酒店，至今内部的装修依旧不过时甚至可以说走到潮流一线。
由于第二天睡过头错过了最爱的酒店早餐，中午去了荔湾亭，虽然有段时间没有来花园酒店的荔湾亭吃饭，但是它的出品依旧在线，非常好评（如果不在意价格的话）。总的来说这次住店体验非常的好，作为广州的招牌之一花园酒店名副其实。最后再次感谢Joe小哥的热情接待。', '2023-02-02', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802813ce3c98b0941765e6d', '广州花园酒店名不虚传，服务态度也太好了叭，特别是前厅部的吴灵伶，入住的时候是她接待我的。服务态度和微笑深深融化了我的心，房间设备非常齐全，卫生也打扫的很棒，干干净净的，为这个酒店点赞，满分。续住碰到前台小妹Betty，潮汕热情的妹妹，点赞！！！', '["https://dimg04.c-ctrip.com/images/0232712000j7xxe3i526C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x12000j7x6vdi57CD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234x12000j7vho3tF4EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000j7wstcz6474_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-21', '城央绿意大床房', '大床房', '朋友出游', 122, 4.812184355372417, 0, 0.0, 1, 0.6931471805599453, 8, '["前台服务", "房间设施", "卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '广州花园酒店名不虚传，服务态度也太好了叭，特别是前厅部的吴灵伶，入住的时候是她接', '广州花园酒店名不虚传，服务态度也太好了叭，特别是前厅部的吴灵伶，入住的时候是她接待我的。服务态度和微笑深深融化了我的心，房间设备非常齐全，卫生也打扫的很棒，干干净净的，为这个酒店点赞，满分。续住碰到前台小妹Betty，潮汕热情的妹妹，点赞！！！', '2025-03-21', 5, '前台服务');
