INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e7c', '先选花园，本来大部分是为了怀旧，毕竟二十年前出差花城常住的酒店，带闺女体验下我大国改革开放之后的第一批豪华酒店。没想到倒是惊喜，酒店应该是把原来的二间房打通变成了一间客房，所以都是套间的布局。基本的硬件不多说了，细节的备品很赞，TWG的茶包Nespresso咖啡和四支屈臣氏的水，白金五星诚不我欺。花园行政酒廊的服务相当周到，热情得我会以为都是刚入行的管培生。除了前台check in排队等候的时间有点长（当然前厅部的水准还是够专业的），一切完美', '["https://dimg04.c-ctrip.com/images/0232l12000anhyofz0ED0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000anh04fmF33C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235112000angz16wB2E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l12000angy9mv6DFF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-12', '红棉双床套房', '套房', '家庭亲子', 223, 5.41164605185504, 0, 0.0, 56, 4.04305126783455, 9, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '先选花园，本来大部分是为了怀旧，毕竟二十年前出差花城常住的酒店，带闺女体验下我大', '先选花园，本来大部分是为了怀旧，毕竟二十年前出差花城常住的酒店，带闺女体验下我大国改革开放之后的第一批豪华酒店。没想到倒是惊喜，酒店应该是把原来的二间房打通变成了一间客房，所以都是套间的布局。基本的硬件不多说了，细节的备品很赞，TWG的茶包Nespresso咖啡和四支屈臣氏的水，白金五星诚不我欺。花园行政酒廊的服务相当周到，热情得我会以为都是刚入行的管培生。除了前台check in排队等候的时间有点长（当然前厅部的水准还是够专业的），一切完美', '2023-02-12', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e7d', '环境好，位置方便，服务热情，过年还准备了很多活动。很满意的一次入住！', '["https://dimg04.c-ctrip.com/images/0230i12000aioyhbgD7DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000aioyqfq9DA6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d12000aioyqgk772B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235712000aioyi794996_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233512000aioyox8D9AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000aioytlzE312_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233212000aioyua7E739_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000aioywcn53A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-27', '红棉大床套房', '套房', '独自旅行', 34, 3.555348061489413, 0, 0.0, 2, 1.0986122886681098, 6, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '环境好，位置方便，服务热情，过年还准备了很多活动。很满意的一次入住！', '环境好，位置方便，服务热情，过年还准备了很多活动。很满意的一次入住！', '2023-01-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e7f', '再次入住花园酒店，还是熟悉的味道。酒店交通极其便利，地铁站步行仅3分钟，周边商圈、美食、景点地很风格
客房环境：
入住的房间空间宽敞，装修典雅兼具现代感。
床品舒适度高，卫浴设施齐全（干湿分离），备品用的是知名品牌，细节贴心。唯一不足是临街房间稍有些噪音，建议大家选择高楼层或或向瀑布的房型。  
服务态度：★★★★★
前台和礼宾部服务热情，办理入住高效，主动介绍了酒店设施和周边推荐。尤其称赞办入住的Cecilia 和BETTY两位前台女生。客房响应速度很快，夜床服务也很细致。  
餐饮体验：
早餐种类丰富，中西式选择多，尤其推荐本地特色的早茶点心。行政酒廊的下午茶安静舒适，适合商务会谈。桃园馆中餐厅的粤菜出品稳定，但晚餐高峰期需等位，不过为了吃好吃的粤菜及特色片皮鸭值得等待', '["https://dimg04.c-ctrip.com/images/0230d12000jbsqwrz250C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233712000jbtchaeFCBB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231912000jbsqws17CF0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236y12000jbt2w4l26FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233812000jbug1pkBF6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2025-03-26', '花园大床房', '大床房', '商务出差', 343, 5.840641657373398, 0, 0.0, 14, 2.70805020110221, 9, '["交通便利性", "房间设施", "前台服务"]'::jsonb, '交通便利性', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '再次入住花园酒店，还是熟悉的味道。酒店交通极其便利，地铁站步行仅3分钟，周边商圈', '再次入住花园酒店，还是熟悉的味道。酒店交通极其便利，地铁站步行仅3分钟，周边商圈、美食、景点地很风格
客房环境：
入住的房间空间宽敞，装修典雅兼具现代感。
床品舒适度高，卫浴设施齐全（干湿分离），备品用的是知名品牌，细节贴心。唯一不足是临街房间稍有些噪音，建议大家选择高楼层或或向瀑布的房型。  
服务态度：★★★★★
前台和礼宾部服务热情，办理入住高效，主动介绍了酒店设施和周边推荐。尤其称赞办入住的Cecilia 和BETTY两位前台女生。客房响应速度很快，夜床服务也很细致。  
餐饮体验：
早餐种类丰富，中西式选择多，尤其推荐本地特色的早茶点心。行政酒廊的下午茶安静舒适，适合商务会谈。桃园馆中餐厅的粤菜出品稳定，但晚餐高峰期需等位，不过为了吃好吃的粤菜及特色片皮鸭值得等待', '2025-03-26', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e80', '前台的mikey，Elvis服务很不错，贴心的按我的要求给我安排房间，而且她们都好温柔哦，人也漂亮，超nice的小姐姐。房间很舒服，布置温馨实用。这次赶时间，下次再试酒店的餐厅，期待他们顶楼的餐厅开放。还有礼宾部的小伙子给我介绍周边的餐厅，出品都好好哦，为我这次广州之行锦上添花。', '["https://dimg04.c-ctrip.com/images/0232x12000aropu4v7359_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233n12000aroplxx987A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234k12000arogxda97C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-13', '花园双床房', '双床房', '朋友出游', 140, 4.948759890378168, 0, 0.0, 3, 1.3862943611198906, 8, '["前台服务", "房间设施", "周边配套"]'::jsonb, '前台服务', '房间设施', '周边配套', '未知酒店', '未知地点', '匿名', '前台的mikey，Elvis服务很不错，贴心的按我的要求给我安排房间，而且她们都', '前台的mikey，Elvis服务很不错，贴心的按我的要求给我安排房间，而且她们都好温柔哦，人也漂亮，超nice的小姐姐。房间很舒服，布置温馨实用。这次赶时间，下次再试酒店的餐厅，期待他们顶楼的餐厅开放。还有礼宾部的小伙子给我介绍周边的餐厅，出品都好好哦，为我这次广州之行锦上添花。', '2023-03-13', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e81', '绝对高大上……服务态度正点……', '["https://dimg04.c-ctrip.com/images/0231t12000aqe6won5873_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000aqe67bd977A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-03', '城央绿意大床房', '大床房', '商务出差', 15, 2.772588722239781, 0, 0.0, 2, 1.0986122886681098, 3, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '绝对高大上……服务态度正点……', '绝对高大上……服务态度正点……', '2023-03-03', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028153e3c98b0941765e84', '早餐真心一般，品种少，服务人员态度友善，比起内地其他五星好太多，花园漂亮。', '["https://dimg04.c-ctrip.com/images/0231a12000afnboglE658_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236v12000afnbl782841_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236x12000afnbmgkDBB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-13', '花园大床房', '大床房', '独自旅行', 37, 3.6375861597263857, 0, 0.0, 50, 3.9318256327243257, 5, '["餐饮设施", "前台服务", "整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '早餐真心一般，品种少，服务人员态度友善，比起内地其他五星好太多，花园漂亮。', '早餐真心一般，品种少，服务人员态度友善，比起内地其他五星好太多，花园漂亮。', '2023-01-13', 4, '餐饮设施');
