INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802815de3c98b0941765e88', '花园酒店是我在广州的这几天住的最好的五星酒店。酒店地理位置优越，出门就是地铁。酒店内部有26个文化打卡点，还有自己的博物馆，值得好好逛一下。房间升级到一室一厅，房内摆设古色古香。值班经理Semmy特别贴心，服务细致周到，待人热情真诚。下次来广州，我一定还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0230712000b7ohnlv81DD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233i12000b7olsyv7836_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000b7oocat5AF2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230812000b7oeoad4CA0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000b7om09n7426_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000b7oh70l32D3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230e12000b7ohcdlF597_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000b7oisfgCE39_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236l12000b7omozjB065_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-13', '花园双床房', '双床房', '家庭亲子', 133, 4.897839799950911, 3, 1.3862943611198906, 4, 1.6094379124341005, 9, '["整体满意度", "交通便利性", "前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店是我在广州的这几天住的最好的五星酒店。酒店地理位置优越，出门就是地铁。酒', '花园酒店是我在广州的这几天住的最好的五星酒店。酒店地理位置优越，出门就是地铁。酒店内部有26个文化打卡点，还有自己的博物馆，值得好好逛一下。房间升级到一室一厅，房内摆设古色古香。值班经理Semmy特别贴心，服务细致周到，待人热情真诚。下次来广州，我一定还住花园酒店。', '2023-05-13', 5, '整体满意度');
