INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028175e3c98b0941765e9d', '这次带家人来广州旅游，选广州花园酒店真选对了，一进门，宽敞明亮的大堂就让人心情舒畅，办理入住的速度很快，工作人员还贴心介绍各项服务。客房的设施设备相当高端，灯光能随心调节，洗浴用品也是，用着很舒服。
