INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281a2e3c98b0941765ec9', '花园酒店服务是真的不错，位置很好很方便，出门就是地铁。服务也很不错，国庆来的时候，酒店送了月饼，前台Betty（也不记得是不是这个名字）非常耐心。酒店餐厅漂亮，家人还去了博物馆参观。唯一就是希望大厅能有些休息的位置，方便离店的时等车的时候老人家有个休息的地方。', '["https://dimg04.c-ctrip.com/images/0236912000crmmbgb1F84_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000crmmf1cFE76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000crmmlj197C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234e12000crmmdnj52A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-20', '花园双床房', '双床房', '家庭亲子', 130, 4.875197323201151, 0, 0.0, 25, 3.258096538021482, 9, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '花园酒店服务是真的不错，位置很好很方便，出门就是地铁。服务也很不错，国庆来的时候', '花园酒店服务是真的不错，位置很好很方便，出门就是地铁。服务也很不错，国庆来的时候，酒店送了月饼，前台Betty（也不记得是不是这个名字）非常耐心。酒店餐厅漂亮，家人还去了博物馆参观。唯一就是希望大厅能有些休息的位置，方便离店的时等车的时候老人家有个休息的地方。', '2023-12-20', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281b1e3c98b0941765ecc', '大堂环境很好，前台Betty也很热情，还有Ellie小姐姐帮忙退房，总之就是很好的体验，下次还会再来！', '["https://dimg04.c-ctrip.com/images/0236m2215g9ejotys1863_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-06', '红棉大床套房', '套房', '商务出差', 51, 3.951243718581428, 0, 0.0, 2, 1.0986122886681098, 6, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '大堂环境很好，前台Betty也很热情，还有Ellie小姐姐帮忙退房，总之就是很好', '大堂环境很好，前台Betty也很热情，还有Ellie小姐姐帮忙退房，总之就是很好的体验，下次还会再来！', '2023-09-06', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281b1e3c98b0941765ecd', '家就住在花园酒店附近，因为来客人了，在携程订了花园酒店二夜住宿。入住时前台Viria小姐姐温柔，耐心，细致，特别是她的笑容，令人有回家的感觉。负责楼层的工作人员态度也非常好，笑容满面，房间收拾得很干净，三天二夜的时光非常愉快。', '["https://dimg04.c-ctrip.com/images/0231n12000bzx3a898874_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000bzx362f5628_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-25', '城央绿意大床房', '大床房', '其他', 113, 4.736198448394496, 0, 0.0, 2, 1.0986122886681098, 8, '["前台服务", "客房服务", "卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '家就住在花园酒店附近，因为来客人了，在携程订了花园酒店二夜住宿。入住时前台Vir', '家就住在花园酒店附近，因为来客人了，在携程订了花园酒店二夜住宿。入住时前台Viria小姐姐温柔，耐心，细致，特别是她的笑容，令人有回家的感觉。负责楼层的工作人员态度也非常好，笑容满面，房间收拾得很干净，三天二夜的时光非常愉快。', '2023-08-25', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281b1e3c98b0941765ece', '三个家庭拖娃带崽自驾出门旅游，在湛江住了同为岭南旗下的湛江花园酒店，各方面很满意。想着广州这个花园酒店会更好毕竟是第一批白金五星酒店， 结果中午三点预订成功两晚三间房  下午七点到店 ，觉得怎么样房间都好了吧，结果七点半给出一间房 剩余两间房就是拿不出来 磨磨唧唧了半天憋出一句让我们去吃了饭回来再给一间 ，我想问问 七点半到店，我们六个大人三个小孩已经够累的了 要是我们已经吃了饭 就想休息的话，那是不是还得按照得前台工作人员贾斯丁说得再去吃饭回来？态度很不好 让人感到很不舒服  说话总是在阴阳或者甩锅给节假日人多之类的 ，具体时效多久能给房间出来也半天都说不出来。结果吃完饭晚上十点回来 才把剩余的两间房给到。酒店这服务，真的不值一千块一晚 。隔音也差，第二天一早就被隔壁的小孩子和电视声音吵醒了。
 很生气就给了个差评  结果又是打电话道歉送自助早餐让删差评之类的  真的能花一千一晚住你酒店真不缺你那个早餐 还让删评论，之前你们干嘛去了。而且都是在我发了差评之后才来联系 所谓的客户关怀 这不恶心人吗？
这酒店是真的不会再来住了', '["https://dimg04.c-ctrip.com/images/0230j12000alhxrot7923_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-02-05', '城央绿意大床房', '大床房', '家庭亲子', 470, 6.154858094016418, 1, 0.6931471805599453, 9, 2.302585092994046, 9, '["前台服务", "退房/入住效率", "安静程度"]'::jsonb, '前台服务', '退房/入住效率', '安静程度', '未知酒店', '未知地点', '匿名', '三个家庭拖娃带崽自驾出门旅游，在湛江住了同为岭南旗下的湛江花园酒店，各方面很满意', '三个家庭拖娃带崽自驾出门旅游，在湛江住了同为岭南旗下的湛江花园酒店，各方面很满意。想着广州这个花园酒店会更好毕竟是第一批白金五星酒店， 结果中午三点预订成功两晚三间房  下午七点到店 ，觉得怎么样房间都好了吧，结果七点半给出一间房 剩余两间房就是拿不出来 磨磨唧唧了半天憋出一句让我们去吃了饭回来再给一间 ，我想问问 七点半到店，我们六个大人三个小孩已经够累的了 要是我们已经吃了饭 就想休息的话，那是不是还得按照得前台工作人员贾斯丁说得再去吃饭回来？态度很不好 让人感到很不舒服  说话总是在阴阳或者甩锅给节假日人多之类的 ，具体时效多久能给房间出来也半天都说不出来。结果吃完饭晚上十点回来 才把剩余的两间房给到。酒店这服务，真的不值一千块一晚 。隔音也差，第二天一早就被隔壁的小孩子和电视声音吵醒了。
 很生气就给了个差评  结果又是打电话道歉送自助早餐让删差评之类的  真的能花一千一晚住你酒店真不缺你那个早餐 还让删评论，之前你们干嘛去了。而且都是在我发了差评之后才来联系 所谓的客户关怀 这不恶心人吗？
这酒店是真的不会再来住了', '2023-02-05', 3, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281b1e3c98b0941765ed1', '服务好，早餐好吃', '["https://dimg04.c-ctrip.com/images/0230m12000agzzqyh36EF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231j12000agzzlm3110B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233f12000agzzpf47CCA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231w12000ah008a1D2D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000ah008gv8175_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-19', '花园双床房', '双床房', '家庭亲子', 8, 2.19722457733622, 0, 0.0, 1, 0.6931471805599453, 3, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务好，早餐好吃', '服务好，早餐好吃', '2023-01-19', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281b1e3c98b0941765ed5', '好好好，还是好', '["https://dimg04.c-ctrip.com/images/0236z12000ahrynd3F185_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000ahrya9x291F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233u12000ahrzguhFEAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-23', '粤韵双床套房', '套房', '家庭亲子', 7, 2.079441541679836, 0, 0.0, 15, 2.772588722239781, 1, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '好好好，还是好', '好好好，还是好', '2023-01-23', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281bee3c98b0941765ed9', '今天生日来广州老牌五星级酒店花园酒店打卡，果然名不虚传，无论环境、酒店设施、服务都是一流。特别表扬一下前台小姐姐Vivia，确实很贴心，见到我们带两个小朋友入住，登记时特意温馨提示介绍了很多儿童的服务，酒店还提供儿童拖鞋及儿童洗刷用品，酒店内有很多艺术打卡点，拍照超出片，餐厅的食品味道正宗，好几家都是米其林餐厅，出品水准高，确实赞！值得二刷！', '["https://dimg04.c-ctrip.com/images/0233712000c3qh09z2CED_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000c3ql3255C58_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000c3qokadD103_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-10', '红棉大床套房', '套房', '家庭亲子', 172, 5.153291594497779, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '今天生日来广州老牌五星级酒店花园酒店打卡，果然名不虚传，无论环境、酒店设施、服务', '今天生日来广州老牌五星级酒店花园酒店打卡，果然名不虚传，无论环境、酒店设施、服务都是一流。特别表扬一下前台小姐姐Vivia，确实很贴心，见到我们带两个小朋友入住，登记时特意温馨提示介绍了很多儿童的服务，酒店还提供儿童拖鞋及儿童洗刷用品，酒店内有很多艺术打卡点，拍照超出片，餐厅的食品味道正宗，好几家都是米其林餐厅，出品水准高，确实赞！值得二刷！', '2023-09-10', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281bee3c98b0941765ede', '酒店不愧是白金五星级酒店，从到达后感觉到服务专业优良一流，门童帮助拿行李，前台接待办理入住的是姓黄的小姐姐，热情周到，提醒事项交待清楚。酒店26个网红打卡点有特色，特别是酒店博物馆有亮点。酒店设施设备，保养良好，卫生到位，有需求反应迅速。下次肯定会再次入住。', '["https://dimg04.c-ctrip.com/images/0235b12000cr8f3e29029_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000cr8gbyc66DE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231k12000cr8jflw0B1E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-12-18', '红棉双床套房', '套房', '朋友出游', 129, 4.867534450455582, 0, 0.0, 20, 3.044522437723423, 9, '["前台服务", "整体满意度", "卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店不愧是白金五星级酒店，从到达后感觉到服务专业优良一流，门童帮助拿行李，前台接', '酒店不愧是白金五星级酒店，从到达后感觉到服务专业优良一流，门童帮助拿行李，前台接待办理入住的是姓黄的小姐姐，热情周到，提醒事项交待清楚。酒店26个网红打卡点有特色，特别是酒店博物馆有亮点。酒店设施设备，保养良好，卫生到位，有需求反应迅速。下次肯定会再次入住。', '2023-12-18', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281c9e3c98b0941765ee0', '放开后的第一次全家旅行选择了广州，四天三晚的行程花园酒店给我留下了深刻的印象。入住因游客众多客房入住等候时间较长，前厅黎经理根据我们一家大小的需求安排我们入住了公寓楼，还赠送了我们两天的早餐，感谢??套房很温馨，有家的感觉。除此之外，酒店的服务细节、瀑布餐厅的景观、大堂的节日氛围、退房的冰箱贴小礼物，都让我们全家十分满意。满分推荐??', '["https://dimg04.c-ctrip.com/images/0236012000ai9m8o05DB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234m12000ai9m8hi04B0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000ai9l6pa99E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000ai9koolE1F1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-25', '红棉大床套房', '套房', '家庭亲子', 168, 5.1298987149230735, 0, 0.0, 7, 2.079441541679836, 9, '["整体满意度", "前台服务", "退房/入住效率"]'::jsonb, '整体满意度', '前台服务', '退房/入住效率', '未知酒店', '未知地点', '匿名', '放开后的第一次全家旅行选择了广州，四天三晚的行程花园酒店给我留下了深刻的印象。入', '放开后的第一次全家旅行选择了广州，四天三晚的行程花园酒店给我留下了深刻的印象。入住因游客众多客房入住等候时间较长，前厅黎经理根据我们一家大小的需求安排我们入住了公寓楼，还赠送了我们两天的早餐，感谢??套房很温馨，有家的感觉。除此之外，酒店的服务细节、瀑布餐厅的景观、大堂的节日氛围、退房的冰箱贴小礼物，都让我们全家十分满意。满分推荐??', '2023-01-25', 5, '整体满意度');
