INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281c9e3c98b0941765ee2', '出差的时候 找了很多 最终还是选择了花园酒店 干净舒适 前台Betty 小姐姐很不错', '["https://dimg04.c-ctrip.com/images/0230112000by164g348A2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-18', '花园大床房', '大床房', '商务出差', 42, 3.7612001156935615, 0, 0.0, 1, 0.6931471805599453, 5, '["整体满意度", "卫生状况", "前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '出差的时候 找了很多 最终还是选择了花园酒店 干净舒适 前台Betty 小姐姐很', '出差的时候 找了很多 最终还是选择了花园酒店 干净舒适 前台Betty 小姐姐很不错', '2023-08-18', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281d4e3c98b0941765eeb', '来到了，来对了，真的体验白金五星花园酒店服务，从下车有拉车门搬行李到门童拉门。眼前大堂气派非凡金碧辉煌非常震撼！房间干净卫生床上用品舒服，每个楼层多有服务生指引按电梯。早餐丰盛人多也不乱。在这里我要感谢大堂经理小郑热情细心为顾客服务，真正体现了花园酒店管理层用心服务于顾客。下次来广州一定再住花园酒店。', '["https://dimg04.c-ctrip.com/images/02366224x8tzimjh03D29_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235d224x8tziue681C76_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c224x8tzipqp570CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p224x8tziue69E19B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-02-08', '花园双床房', '双床房', '情侣出游', 151, 5.0238805208462765, 0, 0.0, 4, 1.6094379124341005, 9, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '来到了，来对了，真的体验白金五星花园酒店服务，从下车有拉车门搬行李到门童拉门。眼', '来到了，来对了，真的体验白金五星花园酒店服务，从下车有拉车门搬行李到门童拉门。眼前大堂气派非凡金碧辉煌非常震撼！房间干净卫生床上用品舒服，每个楼层多有服务生指引按电梯。早餐丰盛人多也不乱。在这里我要感谢大堂经理小郑热情细心为顾客服务，真正体现了花园酒店管理层用心服务于顾客。下次来广州一定再住花园酒店。', '2024-02-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281d4e3c98b0941765eef', '花园酒店太值得去住了，服务到位，过年期间还有好多小活动。虽然是老牌酒店，后期应该翻新过，硬件还可以，房间大小也可以，就是卫生间有点小。
花园里有养了十多年的锦鲤，瀑布绿植，带着小朋友可以玩很久。
酒店的餐厅也相当不错，这次吃了荔枝湾和桃园馆，对于外地游客来说感受特别好。
下次去广州肯定还会入住的。另外要多谢Katherine赠送的一人早餐，可以一家三口一起吃了顿愉快的早餐。', '["https://dimg04.c-ctrip.com/images/0205f12000aiukfrs2892_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0234d12000aiug3ox9442_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-27', '花园大床房', '大床房', '家庭亲子', 188, 5.241747015059643, 0, 0.0, 4, 1.6094379124341005, 9, '["整体满意度", "餐饮设施", "房间设施"]'::jsonb, '整体满意度', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '花园酒店太值得去住了，服务到位，过年期间还有好多小活动。虽然是老牌酒店，后期应该', '花园酒店太值得去住了，服务到位，过年期间还有好多小活动。虽然是老牌酒店，后期应该翻新过，硬件还可以，房间大小也可以，就是卫生间有点小。
花园里有养了十多年的锦鲤，瀑布绿植，带着小朋友可以玩很久。
