INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281dfe3c98b0941765ef5', '花园酒店是一家较国际化的酒店，交通便利，餐饮选择丰富，有小瀑布的花园，很漂亮。30层的下午茶环境好，味道赞。房间设施较好，一切都符合5星的标准。但这次的入住体验很差。是我所有入住酒店换房间最多的1次。酒店下面的地铁正在施工，而且是跨夜施工，工作人员敷衍说他们已经投诉，其实施工一直未停。房间从9层换到7层，我原本套餐标明的房间为18层-21层。换房时在走廊里等了很长时间工作人员开门。还是感谢携程管家奕蓓的多次沟通努力才给换到了高层，其中一晚只能加了一个折叠床。其实酒店工作人员真诚一些，说明情况，我想都可以理解，而搪塞不是对待客人应有的态度。
再次给携程管家奕蓓点赞和感谢。', '["https://dimg04.c-ctrip.com/images/0233f12000coa59t701CF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000coa7u6uDC61_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a12000coabfz3512A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233l12000coab7xd7944_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000coa71893AAA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000coa4suqAD7E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234q12000coac4z5CB8B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000coa5z302FAE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-03', '花园双床房', '双床房', '其他', 288, 5.666426688112432, 0, 0.0, 41, 3.737669618283368, 9, '["安静程度", "前台服务", "房间设施"]'::jsonb, '安静程度', '前台服务', '房间设施', '未知酒店', '未知地点', '匿名', '花园酒店是一家较国际化的酒店，交通便利，餐饮选择丰富，有小瀑布的花园，很漂亮。3', '花园酒店是一家较国际化的酒店，交通便利，餐饮选择丰富，有小瀑布的花园，很漂亮。30层的下午茶环境好，味道赞。房间设施较好，一切都符合5星的标准。但这次的入住体验很差。是我所有入住酒店换房间最多的1次。酒店下面的地铁正在施工，而且是跨夜施工，工作人员敷衍说他们已经投诉，其实施工一直未停。房间从9层换到7层，我原本套餐标明的房间为18层-21层。换房时在走廊里等了很长时间工作人员开门。还是感谢携程管家奕蓓的多次沟通努力才给换到了高层，其中一晚只能加了一个折叠床。其实酒店工作人员真诚一些，说明情况，我想都可以理解，而搪塞不是对待客人应有的态度。
再次给携程管家奕蓓点赞和感谢。', '2023-12-03', 4, '安静程度');
