INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680281f5e3c98b0941765f0b', '多谢前台betty升级亲子套房，服务态度很好！工作人员素质挺高的。设施有点老，但酒店整体文化氛围浓厚，还是很值得一住。博物馆，餐厅，花园，离机场也很近，满足本次出游目的！小孩子也很开心
荔湾庭大部分工作人员态度还是很好的，味道也还行，烧鹅有点失望，付款的时候账单有问题，付款完才看到，收款的小姐姐直接在旁边跟同事吐槽的语气说我给了钱才说，不像五星级餐厅的态度
另外早餐环境取胜，整体上吃的都有点没满足期待', '["https://dimg04.c-ctrip.com/images/0232l12000bul9pdk590C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000bulb2qi7A7B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233k12000bul9pxdF51E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-08-07', '花园大床房', '大床房', '家庭亲子', 204, 5.3230099791384085, 1, 0.6931471805599453, 3, 1.3862943611198906, 7, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '多谢前台betty升级亲子套房，服务态度很好！工作人员素质挺高的。设施有点老，但', '多谢前台betty升级亲子套房，服务态度很好！工作人员素质挺高的。设施有点老，但酒店整体文化氛围浓厚，还是很值得一住。博物馆，餐厅，花园，离机场也很近，满足本次出游目的！小孩子也很开心
荔湾庭大部分工作人员态度还是很好的，味道也还行，烧鹅有点失望，付款的时候账单有问题，付款完才看到，收款的小姐姐直接在旁边跟同事吐槽的语气说我给了钱才说，不像五星级餐厅的态度
另外早餐环境取胜，整体上吃的都有点没满足期待', '2023-08-07', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028201e3c98b0941765f19', '大环境非常不错，门厅气派，花园不错。房间老旧了，这不是问题，老的依旧可以很气质，但是墙面低处的痕迹，脏污无法处理干净，就显得有点不那么协调。早餐不好吃，比较失望，下午茶也是。下午茶的服务很拉垮，泡杯茶久久不来，看个行政酒廊卡，来回3波人，要求看了4次，有点怀疑到底再弄什么。酒店氛围也还不错，4楼有博物馆，可以一看，有些意思。大堂有意思，也值得欣赏欣赏。位置还可以，对面有友谊商场，广州酒家，后面有很多吃的店，记得有一家点都德，打的方便，叫车也方便，出门就有地铁口。房间内有环市东路一日游指南，这个不错。退房当天恰逢其38周年庆布置，氛围还是很好的。提一下，办理出入的Joe礼貌认真。', '["https://dimg04.c-ctrip.com/images/0234012000c0l7juj0A78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g12000c0ldfkg6DE1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232b12000c0l4dat2FD9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-08-27', '花园双床房', '双床房', '家庭亲子', 292, 5.680172609017068, 0, 0.0, 8, 2.19722457733622, 8, '["周边配套", "房间设施", "餐饮设施"]'::jsonb, '周边配套', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '大环境非常不错，门厅气派，花园不错。房间老旧了，这不是问题，老的依旧可以很气质，', '大环境非常不错，门厅气派，花园不错。房间老旧了，这不是问题，老的依旧可以很气质，但是墙面低处的痕迹，脏污无法处理干净，就显得有点不那么协调。早餐不好吃，比较失望，下午茶也是。下午茶的服务很拉垮，泡杯茶久久不来，看个行政酒廊卡，来回3波人，要求看了4次，有点怀疑到底再弄什么。酒店氛围也还不错，4楼有博物馆，可以一看，有些意思。大堂有意思，也值得欣赏欣赏。位置还可以，对面有友谊商场，广州酒家，后面有很多吃的店，记得有一家点都德，打的方便，叫车也方便，出门就有地铁口。房间内有环市东路一日游指南，这个不错。退房当天恰逢其38周年庆布置，氛围还是很好的。提一下，办理出入的Joe礼貌认真。', '2023-08-27', 3, '周边配套');
