INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028217e3c98b0941765f2d', '这是一篇好评！
环境：我们从地铁站下车，正面看起来感觉是普通五星，一走进去就被壁画震撼到！整个酒店内部装饰很大气有质感，办理入住的时候就一整个期待住了！
设施： 可能定期在翻修换新，房间内部设施没有想象中的那么老旧，还OK，石材也都保养的很好！
服务：最值得夸的就是服务了，从一入住开始，前台接待员Tony小麦很热心的办理了服务，因为我们是两个订单，所以需要合并再操作，整个过程他都很热心帮我们处理问题！我们住了三天，行政酒廊的Carrie和Danli都非常细心，期间我包包落在餐厅，拿到后第二天Carrie还有关心问询，非常暖心。接待处的小洪也很热情！
这次广州游本来在连锁酒店跟老牌五星之间纠结，运气很好选了花园酒店，期间整个入住感受服务体验都为我们这次广州行添了不少高光时刻！
如果你跟我一样出行很看重服务的话，花园真的值得??！', '["https://dimg04.c-ctrip.com/images/0230612000aqjmqwwF687_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234012000aqjgmf5F7D0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-04', '花园双床房', '双床房', '情侣出游', 368, 5.910796644040527, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "整体满意度", "交通便利性"]'::jsonb, '前台服务', '整体满意度', '交通便利性', '未知酒店', '未知地点', '匿名', '这是一篇好评！', '这是一篇好评！
环境：我们从地铁站下车，正面看起来感觉是普通五星，一走进去就被壁画震撼到！整个酒店内部装饰很大气有质感，办理入住的时候就一整个期待住了！
设施： 可能定期在翻修换新，房间内部设施没有想象中的那么老旧，还OK，石材也都保养的很好！
服务：最值得夸的就是服务了，从一入住开始，前台接待员Tony小麦很热心的办理了服务，因为我们是两个订单，所以需要合并再操作，整个过程他都很热心帮我们处理问题！我们住了三天，行政酒廊的Carrie和Danli都非常细心，期间我包包落在餐厅，拿到后第二天Carrie还有关心问询，非常暖心。接待处的小洪也很热情！
这次广州游本来在连锁酒店跟老牌五星之间纠结，运气很好选了花园酒店，期间整个入住感受服务体验都为我们这次广州行添了不少高光时刻！
如果你跟我一样出行很看重服务的话，花园真的值得??！', '2023-03-04', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028227e3c98b0941765f34', '酒店就在地铁口，出行很方便。凌晨入住，酒店前台小钟热情办好了入住。当天赶上水管维修，早上酒店工作人员协调去另外一栋楼的房间洗漱，解决问题很及时。', '["https://dimg04.c-ctrip.com/images/0234t12000bodovc3DC5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234912000bodos00C55A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234g12000bodor8m37E9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230112000bodor8w70BD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-07-17', '花园双床房', '双床房', '家庭亲子', 72, 4.290459441148391, 0, 0.0, 19, 2.995732273553991, 8, '["交通便利性", "前台服务", "客房服务"]'::jsonb, '交通便利性', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '酒店就在地铁口，出行很方便。凌晨入住，酒店前台小钟热情办好了入住。当天赶上水管维', '酒店就在地铁口，出行很方便。凌晨入住，酒店前台小钟热情办好了入住。当天赶上水管维修，早上酒店工作人员协调去另外一栋楼的房间洗漱，解决问题很及时。', '2023-07-17', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028227e3c98b0941765f35', '地理位置超级好就在地铁站边上，前台接的的小姐姐Rebecca小钟服务很热情还升级送了早餐，赞了赞了', '["https://dimg04.c-ctrip.com/images/0235112000arrglauFC18_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000arrn35t93D3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-14', '花园大床房', '大床房', '商务出差', 49, 3.912023005428146, 0, 0.0, 10, 2.3978952727983707, 8, '["交通便利性", "前台服务", "餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '地理位置超级好就在地铁站边上，前台接的的小姐姐Rebecca小钟服务很热情还升级', '地理位置超级好就在地铁站边上，前台接的的小姐姐Rebecca小钟服务很热情还升级送了早餐，赞了赞了', '2023-03-14', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028227e3c98b0941765f36', '虽然来过广州很多次，但是第一次入住花园酒店。就是冲着酒店的悠久历史和人文文化来的。非常感谢协助办理入住的前台工作人员Ken，看到我们有小朋友积极帮我们协调房间，并跑前跑后找经理帮我们升级了房型，而且还很耐心的讲解酒店的历史和文化。很耐心的解答我们的各种问题，而且怕我们找不到电梯，还主动送我们到电梯口！酒店的早餐也非常丰富，而且还是旋转餐厅，可以看到小蛮腰！孩子上午一直在酒店泳池内游泳，水质也很干净，工作人员主动提供的饮料和白水。
入住的整体感觉还是非常不错的，下次有机会还会选择花园酒店！再次感谢前台工作人员Ken，让整个十一的广州假期画上了圆满的句号！', '["https://dimg04.c-ctrip.com/images/0232a12000ce5cmyz6AFF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234512000ce5a528D508_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000ce5dhag4693_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000ce59kgm1A47_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-15', '花园双床房', '双床房', '家庭亲子', 279, 5.634789603169249, 0, 0.0, 1, 0.6931471805599453, 9, '["前台服务", "餐饮设施", "公共设施"]'::jsonb, '前台服务', '餐饮设施', '公共设施', '未知酒店', '未知地点', '匿名', '虽然来过广州很多次，但是第一次入住花园酒店。就是冲着酒店的悠久历史和人文文化来的', '虽然来过广州很多次，但是第一次入住花园酒店。就是冲着酒店的悠久历史和人文文化来的。非常感谢协助办理入住的前台工作人员Ken，看到我们有小朋友积极帮我们协调房间，并跑前跑后找经理帮我们升级了房型，而且还很耐心的讲解酒店的历史和文化。很耐心的解答我们的各种问题，而且怕我们找不到电梯，还主动送我们到电梯口！酒店的早餐也非常丰富，而且还是旋转餐厅，可以看到小蛮腰！孩子上午一直在酒店泳池内游泳，水质也很干净，工作人员主动提供的饮料和白水。
入住的整体感觉还是非常不错的，下次有机会还会选择花园酒店！再次感谢前台工作人员Ken，让整个十一的广州假期画上了圆满的句号！', '2023-10-15', 5, '前台服务');
