INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028249e3c98b0941765f53', '非常惊喜又满意的入住体验！自己带儿子入住，意外的升级到套房，还赠送两份早餐，下午茶和晚上happy hour 的餐食，真是不能更幸运啦！感谢Betty热情和体贴！
