INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028253e3c98b0941765f58', '第一次入住花园酒店，酒店环境不错，工作人员服务效率很高，入住当天在停车场不小心遗失钓具，凌晨两三点发现，马上告知前台，半个小时左右前台电话通知有发现疑似物品需去前台确认，马上下楼去前台确认，很是感激那晚酒店值班员工Jay，非常感谢??', '["https://dimg04.c-ctrip.com/images/0236a12000agdwzm11A38_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000agdzxexF93C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000age0dpy28F4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-16', '花园大床房', '大床房', '情侣出游', 117, 4.770684624465665, 0, 0.0, 7, 2.079441541679836, 8, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '第一次入住花园酒店，酒店环境不错，工作人员服务效率很高，入住当天在停车场不小心遗', '第一次入住花园酒店，酒店环境不错，工作人员服务效率很高，入住当天在停车场不小心遗失钓具，凌晨两三点发现，马上告知前台，半个小时左右前台电话通知有发现疑似物品需去前台确认，马上下楼去前台确认，很是感激那晚酒店值班员工Jay，非常感谢??', '2023-01-16', 5, '前台服务');
