INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028254e3c98b0941765f61', '预定的是花园酒店的木棉房，因故换成了粤韵房。接待我们姓刘的女经理十分亲切，及时帮我们解决了问题。粤韵房间很舒适。
    酒店大堂十分喜庆漂亮。
    订房时购买套餐里赠送的行政礼遇十分满意。特别是锦鲤行政酒廊两位帅哥美女（美女是印度籍的外籍人士）的服务十分周到细致。我们住宿了二个晚上，去了三次锦鲤酒廊，他们一直热情服务。必须给予一个大大的赞。
    早餐因为是行政礼遇的涵盖，在二楼荔湾亭，环境十分优雅，菜品很丰富可口，基本都是广州的特色小吃。
    一次十分满意的住宿。
   值得推荐。
设施：木棉房比较陈旧了。
环境：大堂和后花园瀑布特别漂亮
服务：很好
