INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802825ee3c98b0941765f62', '花园酒店已经不记得住过多少次了，每次只要到广州就会住在这里，房间一如既往的舒适，工作人员热情周到，这次妈妈独自去办入住，受到工作人员Vivia的热情接待，妈妈很开心，一直跟我说花园酒店的服务真好，酒店设施齐全，花园也很美。推荐到广州的朋友，一定要到花园酒店来体验一下。', '["https://dimg04.c-ctrip.com/images/0232m12000bdklvj8CB55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000bdkscryADF5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-08', '花园大床房', '大床房', '家庭亲子', 134, 4.90527477843843, 0, 0.0, 2, 1.0986122886681098, 8, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '花园酒店已经不记得住过多少次了，每次只要到广州就会住在这里，房间一如既往的舒适，', '花园酒店已经不记得住过多少次了，每次只要到广州就会住在这里，房间一如既往的舒适，工作人员热情周到，这次妈妈独自去办入住，受到工作人员Vivia的热情接待，妈妈很开心，一直跟我说花园酒店的服务真好，酒店设施齐全，花园也很美。推荐到广州的朋友，一定要到花园酒店来体验一下。', '2023-06-08', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802825ee3c98b0941765f64', '不愧是广州的老牌星级酒店，大堂装修富丽堂皇，办理入住得前台Jessie 很nice，耐心解答我们的疑问，知道有小朋友生日还安排送了我们小点心～
酒店的花园真的美，特别是瀑布位置，晚上自助餐的位置可以看到瀑布，不过要提前去取号，因为位置是根据取号先到先选的。自助晚餐品类不是特别多，但够精，刺身都很新鲜。
我们的自助早餐是酒店二楼的中式餐厅，品种挺多的，味道也不错，服务员的态度很好??', '["https://dimg04.c-ctrip.com/images/0232612000aqpffw57947_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230y12000aqpm1v06B67_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235812000aqpgi221F5F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235312000aqpgjysD433_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234f12000aqpm5fc860A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236o12000aqpitwj9D73_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000aqpeqjg5BD6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-05', '粤韵双床套房', '套房', '家庭亲子', 192, 5.262690188904886, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '不愧是广州的老牌星级酒店，大堂装修富丽堂皇，办理入住得前台Jessie 很nic', '不愧是广州的老牌星级酒店，大堂装修富丽堂皇，办理入住得前台Jessie 很nice，耐心解答我们的疑问，知道有小朋友生日还安排送了我们小点心～
酒店的花园真的美，特别是瀑布位置，晚上自助餐的位置可以看到瀑布，不过要提前去取号，因为位置是根据取号先到先选的。自助晚餐品类不是特别多，但够精，刺身都很新鲜。
我们的自助早餐是酒店二楼的中式餐厅，品种挺多的，味道也不错，服务员的态度很好??', '2023-03-05', 5, '前台服务');
