服务：不愧是白金五星，前台Ann特别暖心帮我们升级服务，对广州酒店业印象非常好；这次带孩子来房间服务很到位，Tina特别仔细房间服务非常好，下次还住花园酒店！', '2025-01-27', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802826be3c98b0941765f74', '环境很好很安静 到酒店的时候办理入住的人很多 后来是大厅的麦经理主动帮我们办理入住 服务态度非常好～下次来还会选择花园酒店入住的～', '["https://dimg04.c-ctrip.com/images/0235y12000ap30a6y5FEA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234a12000ap37gmm7890_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-21', '花园双床房', '双床房', '朋友出游', 65, 4.189654742026425, 0, 0.0, 1, 0.6931471805599453, 7, '["前台服务", "安静程度", "整体满意度"]'::jsonb, '前台服务', '安静程度', '整体满意度', '未知酒店', '未知地点', '匿名', '环境很好很安静 到酒店的时候办理入住的人很多 后来是大厅的麦经理主动帮我们办理入', '环境很好很安静 到酒店的时候办理入住的人很多 后来是大厅的麦经理主动帮我们办理入住 服务态度非常好～下次来还会选择花园酒店入住的～', '2023-02-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028276e3c98b0941765f7c', '住了很多次的酒店，环境不错。出行也方便就在市中心，毕竟老牌酒店了。接待的前台好像叫Rebecca，态度挺好还送了两支花！', '["https://dimg04.c-ctrip.com/images/0236712000bazkwv21C7C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236t12000bazjw25BCE4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235z12000bazlb876529_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k12000bazi3tbAFFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-27', '红棉大床套房', '套房', '商务出差', 60, 4.110873864173311, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '住了很多次的酒店，环境不错。出行也方便就在市中心，毕竟老牌酒店了。接待的前台好像', '住了很多次的酒店，环境不错。出行也方便就在市中心，毕竟老牌酒店了。接待的前台好像叫Rebecca，态度挺好还送了两支花！', '2023-05-27', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028280e3c98b0941765f81', '位置不错，环境绝佳，服务不错，大堂经理很有礼貌，尤其是管家小刘服务太到位了，整体是不错的体验。但是当天办理入住的前台真是太差劲了，已经不是服务好不好的问题，简直是毫无“人性”，下午2点多到酒店，询问了她价格后感觉携程优惠力度还是比较大的，就在携程下了订单，但被告知携程订单要等一个多小时，给她说了孩子还没吃饭能不能提前办理，说不可以。无奈之下，就去问大堂服务人员有没有能吃饭的地方，服务员说暂时没有，但还是很耐心的帮忙找了个很小的地方。后来，几经询问，说没有规定网上订单必须等一个小时，就又去前台询问，她说可以办理，等候是我们自己同意的，真是无语了，简直坏的很。', '["https://dimg04.c-ctrip.com/images/0231f12000ejjioe89C3F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v12000ejjf1tpA388_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000ejjdhiwB19A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-21', '花园双床房', '双床房', '家庭亲子', 281, 5.641907070938114, 0, 0.0, 6, 1.9459101490553128, 9, '["前台服务", "整体满意度", "退房/入住效率"]'::jsonb, '前台服务', '整体满意度', '退房/入住效率', '未知酒店', '未知地点', '匿名', '位置不错，环境绝佳，服务不错，大堂经理很有礼貌，尤其是管家小刘服务太到位了，整体', '位置不错，环境绝佳，服务不错，大堂经理很有礼貌，尤其是管家小刘服务太到位了，整体是不错的体验。但是当天办理入住的前台真是太差劲了，已经不是服务好不好的问题，简直是毫无“人性”，下午2点多到酒店，询问了她价格后感觉携程优惠力度还是比较大的，就在携程下了订单，但被告知携程订单要等一个多小时，给她说了孩子还没吃饭能不能提前办理，说不可以。无奈之下，就去问大堂服务人员有没有能吃饭的地方，服务员说暂时没有，但还是很耐心的帮忙找了个很小的地方。后来，几经询问，说没有规定网上订单必须等一个小时，就又去前台询问，她说可以办理，等候是我们自己同意的，真是无语了，简直坏的很。', '2024-06-21', 4, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028280e3c98b0941765f82', '花园酒店，绝对是我入住过众多星级酒店里的TOP 1，白金五星酒店的名号，名不虚传。
房间宽敞，设施齐全，Mini bar，胶囊咖啡，JBL音响，办公桌，沙发，一应俱全。
当得知入住当天，是我家先生的生日，提前布置好房间，还送了生日蛋糕，非常贴心和暖心。
酒店有4家入选米其林指南的餐厅，各式美食应有尽有。
多谢前台小姐姐Gillian和Betty在入住和离店期间的热情接待，温柔耐心，详细地介绍了酒店的网红打卡点，让我们有了一次美好的度假体验。', '["https://dimg04.c-ctrip.com/images/0231612000c2wwj2v3ED0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k12000c2wl8t0514C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234c12000c2wo3p890B7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235912000c2wlss6C3A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000c2wqucp8F10_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000c2x3knqF193_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232e12000c2x3a4yB898_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-06', '红棉大床套房', '套房', '其他', 222, 5.407171771460119, 0, 0.0, 9, 2.302585092994046, 9, '["整体满意度", "房间设施", "前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店，绝对是我入住过众多星级酒店里的TOP 1，白金五星酒店的名号，名不虚传', '花园酒店，绝对是我入住过众多星级酒店里的TOP 1，白金五星酒店的名号，名不虚传。
房间宽敞，设施齐全，Mini bar，胶囊咖啡，JBL音响，办公桌，沙发，一应俱全。
当得知入住当天，是我家先生的生日，提前布置好房间，还送了生日蛋糕，非常贴心和暖心。
酒店有4家入选米其林指南的餐厅，各式美食应有尽有。
