INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028280e3c98b0941765f84', '酒店环境真的不错，服务态度也很好，住宿环境舒适！再次遇见Maggie还是特别仔细和热情，再次提出表扬！', '["https://dimg04.c-ctrip.com/images/0235l12000aqnxo6tB902_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-05', '红棉大床套房', '套房', '独自旅行', 51, 3.951243718581428, 0, 0.0, 6, 1.9459101490553128, 6, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店环境真的不错，服务态度也很好，住宿环境舒适！再次遇见Maggie还是特别仔细', '酒店环境真的不错，服务态度也很好，住宿环境舒适！再次遇见Maggie还是特别仔细和热情，再次提出表扬！', '2023-03-05', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802829be3c98b0941765f98', '多次来广州，第一次入住广州花园酒店，一进门就被大堂绚丽的装饰所吸引，服务人员都面带笑容迎接客人的到来～到前台有序办理入住，我们预订的是普通大床房，办理时还需要等待房间收拾出来，特别需要感谢前台接待我们的服务人员，名字叫梁婉彤，当看到我们四岁的儿子快要睡着了就立即给我们升级了儿童套房，孩子进到房间立即被房间里的游乐设施所吸引，高兴坏了～早餐也很好，外面就是酒店园林还有瀑布，赞??入住期间还参观了属于酒店的博物馆，了解了酒店的历史，广州花园酒店还是邓小平给题的词，很有文化和历史的酒店，1981年建设的到现在感觉都不太落伍，可能是我比较喜欢这类风格吧！总之下次来广州一定会优先选择广州花园酒店', '["https://dimg04.c-ctrip.com/images/0230a12000al699qlF8C4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232812000al5mkns8317_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000al5gyjb1FDD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233x12000al52tvi07AD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230d12000al6ci67960C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236p12000al66n1s3BFE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232612000al5qztvFD9A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231d12000al5u6p90FCC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-04', '花园大床房', '大床房', '家庭亲子', 296, 5.6937321388027, 0, 0.0, 14, 2.70805020110221, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '多次来广州，第一次入住广州花园酒店，一进门就被大堂绚丽的装饰所吸引，服务人员都面', '多次来广州，第一次入住广州花园酒店，一进门就被大堂绚丽的装饰所吸引，服务人员都面带笑容迎接客人的到来～到前台有序办理入住，我们预订的是普通大床房，办理时还需要等待房间收拾出来，特别需要感谢前台接待我们的服务人员，名字叫梁婉彤，当看到我们四岁的儿子快要睡着了就立即给我们升级了儿童套房，孩子进到房间立即被房间里的游乐设施所吸引，高兴坏了～早餐也很好，外面就是酒店园林还有瀑布，赞??入住期间还参观了属于酒店的博物馆，了解了酒店的历史，广州花园酒店还是邓小平给题的词，很有文化和历史的酒店，1981年建设的到现在感觉都不太落伍，可能是我比较喜欢这类风格吧！总之下次来广州一定会优先选择广州花园酒店', '2023-02-04', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802829be3c98b0941765f99', '1.地理位置：酒店地理位置出行方便，门口就有等位的出租车，酒店大门口就有地铁站淘金站。
2.服务态度：很棒，特别是帮忙办理入住的Dorn,甜美可爱，服务态度也很好。
3.酒店服务：早自助还有3个不同的餐厅，其中瀑布餐厅环节优美，是偏西式的餐厅。2楼有个荔湾庭偏中式，也不错。下午和晚上还提供茶歇，非常便捷。', '["https://dimg04.c-ctrip.com/images/0233o12000c3cpgttB619_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232t12000c3cpdiiA204_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000c3cinakD140_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000c3cpccv199A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000c3cpkb9395B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000c3cq1cmEE78_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234i12000c3cm25b8951_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233r12000c3cjt079CE7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231y12000c3ct5bu51F6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-08', '花园双床房', '双床房', '家庭亲子', 153, 5.0369526024136295, 2, 1.0986122886681098, 1, 0.6931471805599453, 8, '["交通便利性", "前台服务", "餐饮设施"]'::jsonb, '交通便利性', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '1.地理位置：酒店地理位置出行方便，门口就有等位的出租车，酒店大门口就有地铁站淘', '1.地理位置：酒店地理位置出行方便，门口就有等位的出租车，酒店大门口就有地铁站淘金站。
2.服务态度：很棒，特别是帮忙办理入住的Dorn,甜美可爱，服务态度也很好。
3.酒店服务：早自助还有3个不同的餐厅，其中瀑布餐厅环节优美，是偏西式的餐厅。2楼有个荔湾庭偏中式，也不错。下午和晚上还提供茶歇，非常便捷。', '2023-09-08', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802829be3c98b0941765f9c', '酒店很气派，过年时间有骑着大公鸡吹喇叭的人，有吹气球的小丑，酒店位置很棒，酒店里居然有大瀑布和大锦鲤，在这里点名表扬kiki，宝宝爸爸眼镜掉到了鱼池子里，Kiki立马组织帮助打捞，特别棒！酒店也很棒！还有超大泳池', '["https://dimg04.c-ctrip.com/images/0231612000aitn60w89AC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234b12000aitjolt5AAB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-27', '城央绿意双床房', '双床房', '家庭亲子', 106, 4.672828834461906, 0, 0.0, 47, 3.871201010907891, 8, '["公共设施", "前台服务", "整体满意度"]'::jsonb, '公共设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店很气派，过年时间有骑着大公鸡吹喇叭的人，有吹气球的小丑，酒店位置很棒，酒店里', '酒店很气派，过年时间有骑着大公鸡吹喇叭的人，有吹气球的小丑，酒店位置很棒，酒店里居然有大瀑布和大锦鲤，在这里点名表扬kiki，宝宝爸爸眼镜掉到了鱼池子里，Kiki立马组织帮助打捞，特别棒！酒店也很棒！还有超大泳池', '2023-01-27', 5, '公共设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802829be3c98b0941765f9d', '位置一流！去哪都不远，附近好吃的很多。
设施一流！酒店里就有三个米其林，样样好吃。
