INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282c8e3c98b0941765fbe', '年后出行，到店已经傍晚了，老牌酒店，大堂还是很气派的。门口的服务生看到客人很有服务意识。到了前台，Billy查询到我们定的房间还不能入住，给我们升级了套房还送了早餐。床垫很舒服，卫生间也很大。当天入住生日，酒店还送了蛋糕，住了2天后又续房了。酒店的早餐环境很棒，可以看到花园的瀑布，餐食就比较普通，我觉得到了广州真的没必要在酒店吃，酒店的桃园馆用餐环境也是一级棒，很有广东的特色，很中式，菜品么真的是不及它的环境，不过服务还是很棒的。所以还是很推荐入住这家酒店，服务非常好，除了餐饮不推荐。', '["https://dimg04.c-ctrip.com/images/0234712000ajmdx3nB160_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000ajmiw5i4E83_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000ajmas3t5B6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236f12000ajm6vfpB0F5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000ajmb3xfB29F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230512000ajm6yz530F7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000ajmckc53635_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232312000ajmecssFA6D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-31', '花园双床房', '双床房', '家庭亲子', 245, 5.5053315359323625, 0, 0.0, 7, 2.079441541679836, 9, '["前台服务", "整体满意度", "餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '年后出行，到店已经傍晚了，老牌酒店，大堂还是很气派的。门口的服务生看到客人很有服', '年后出行，到店已经傍晚了，老牌酒店，大堂还是很气派的。门口的服务生看到客人很有服务意识。到了前台，Billy查询到我们定的房间还不能入住，给我们升级了套房还送了早餐。床垫很舒服，卫生间也很大。当天入住生日，酒店还送了蛋糕，住了2天后又续房了。酒店的早餐环境很棒，可以看到花园的瀑布，餐食就比较普通，我觉得到了广州真的没必要在酒店吃，酒店的桃园馆用餐环境也是一级棒，很有广东的特色，很中式，菜品么真的是不及它的环境，不过服务还是很棒的。所以还是很推荐入住这家酒店，服务非常好，除了餐饮不推荐。', '2023-01-31', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282c8e3c98b0941765fbf', '办理入住的时候特别顺畅，感谢Gogo小哥哥的帮助。房间很干净，整体给人感觉特别好，下次来广州还会再来的??楼下的桃园馆餐厅也非常不错', '["https://dimg04.c-ctrip.com/images/0231612000aolqp000D04_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232y12000aolqp021167_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-17', '红棉大床套房', '套房', '商务出差', 66, 4.204692619390966, 0, 0.0, 4, 1.6094379124341005, 7, '["前台服务", "卫生状况", "整体满意度"]'::jsonb, '前台服务', '卫生状况', '整体满意度', '未知酒店', '未知地点', '匿名', '办理入住的时候特别顺畅，感谢Gogo小哥哥的帮助。房间很干净，整体给人感觉特别好', '办理入住的时候特别顺畅，感谢Gogo小哥哥的帮助。房间很干净，整体给人感觉特别好，下次来广州还会再来的??楼下的桃园馆餐厅也非常不错', '2023-02-17', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282c8e3c98b0941765fc1', '花园酒店，白金五星级酒店，这里的员工热情有礼，入住时接待员billy的热情接待办理入住，再到礼宾部经理Tim和John的热情介绍酒店周边景点，酒店娱乐设施，寄存行李服务高效快捷，当客人入住后，礼宾部经理Tim亲自将客人寄存在礼宾部的行李送到客人房间并祝客人有个开心愉快的私人假期。行政酒廊李经理，员工Zoey，印度籍员工Carrily为客人提供人性化的用餐服务，得知客人有老人同行，老人家对于欢乐时光餐点有一些吃不惯，马上为老人家准备了两碗热气腾腾的汤粉，早餐对于客人只是提及一些小建议时，印度籍员工Carrily对于客人的建议及时反馈并处理，得到客人的点赞。晚上房间有点冷，致电总机后15楼服务员得知后立马找来一台暖风机给客人使用，因为匆忙，没来得及记下这位女服务员的名字，不过总体来说，花园的服务的确不错，给客人一种真正回到家的温馨感觉。', '["https://dimg04.c-ctrip.com/images/0233b12000al8ht33CBAD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233g12000al7yhos5026_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000al8l21iAF3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236m12000al7pokb09FA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232012000al8it8v64CC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000al8vt0f432B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230612000al8cd272203_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000al7n0ro11E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231g12000al8ljp2B055_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-02-04', '红棉大床套房', '套房', '独自旅行', 371, 5.918893854273146, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "客房服务", "餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '花园酒店，白金五星级酒店，这里的员工热情有礼，入住时接待员billy的热情接待办', '花园酒店，白金五星级酒店，这里的员工热情有礼，入住时接待员billy的热情接待办理入住，再到礼宾部经理Tim和John的热情介绍酒店周边景点，酒店娱乐设施，寄存行李服务高效快捷，当客人入住后，礼宾部经理Tim亲自将客人寄存在礼宾部的行李送到客人房间并祝客人有个开心愉快的私人假期。行政酒廊李经理，员工Zoey，印度籍员工Carrily为客人提供人性化的用餐服务，得知客人有老人同行，老人家对于欢乐时光餐点有一些吃不惯，马上为老人家准备了两碗热气腾腾的汤粉，早餐对于客人只是提及一些小建议时，印度籍员工Carrily对于客人的建议及时反馈并处理，得到客人的点赞。晚上房间有点冷，致电总机后15楼服务员得知后立马找来一台暖风机给客人使用，因为匆忙，没来得及记下这位女服务员的名字，不过总体来说，花园的服务的确不错，给客人一种真正回到家的温馨感觉。', '2023-02-04', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282c8e3c98b0941765fc4', '春节期间入住酒店，后花园特别惊艳，大厅布置的喜气洋洋、充满过年气息！使人精神特别愉悦！酒店房间确实有些年代感、但胜在酒店的历史和服务！实名感谢行政酒廊的CARRIE小姐姐服务到位、热情洋溢！还要感谢大堂的小花小姐姐给我们及时解决了加床问题！花园酒店、特别喜欢！会再来哦！', '["https://dimg04.c-ctrip.com/images/0234l12000ailhbwoCD97_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236512000ailh9zcBFBF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-27', '花园行政双床套房', '套房', '家庭亲子', 135, 4.912654885736052, 0, 0.0, 2, 1.0986122886681098, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '春节期间入住酒店，后花园特别惊艳，大厅布置的喜气洋洋、充满过年气息！使人精神特别', '春节期间入住酒店，后花园特别惊艳，大厅布置的喜气洋洋、充满过年气息！使人精神特别愉悦！酒店房间确实有些年代感、但胜在酒店的历史和服务！实名感谢行政酒廊的CARRIE小姐姐服务到位、热情洋溢！还要感谢大堂的小花小姐姐给我们及时解决了加床问题！花园酒店、特别喜欢！会再来哦！', '2023-01-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282c8e3c98b0941765fc5', '不错的酒店体验 花园太赞了 服务很棒 下电梯就有EllIE小姐姐可以解决我们的各种疑问', '["https://dimg04.c-ctrip.com/images/0233n12000b658q8k677E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233a12000b65ceyhF0A7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e12000b65coeo765B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235v12000b65joz1ADCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-05-06', '红棉大床套房', '套房', '家庭亲子', 43, 3.784189633918261, 0, 0.0, 2, 1.0986122886681098, 6, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '不错的酒店体验 花园太赞了 服务很棒 下电梯就有EllIE小姐姐可以解决我们的各', '不错的酒店体验 花园太赞了 服务很棒 下电梯就有EllIE小姐姐可以解决我们的各种疑问', '2023-05-06', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282d4e3c98b0941765fc6', '不愧是国内仅有的三家白金五星级酒店之一。虽然有些年头了，但是维护的很不错。大堂金碧辉煌的，随处可见的兰花。酒店园景也超棒。你能相信在广州城中的酒店能有如此美的园景。4楼还有一个酒店自身的博物馆。酒店的服务也很好，每个工作人员都很专业。尤其是前台帮我们办理入住的viria小姐姐。态度特别好，很专业，还给我们升级了房间。房间比较新，应该是新装修过了。同时酒店的早餐也不错，种类多，味道好。酒店整体还是非常推荐的，尤其适合带老人家体验。', '["https://dimg04.c-ctrip.com/images/0231r12000bhsht3w0DBA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000bhskppn9ECC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000bhs0tmsEF72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a12000bhrwthpD064_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235r12000bhrpoqcB9E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p12000bhsaqo68FF4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-06-25', '红棉大床套房', '套房', '情侣出游', 216, 5.37989735354046, 0, 0.0, 9, 2.302585092994046, 9, '["整体满意度", "前台服务", "餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施', '未知酒店', '未知地点', '匿名', '不愧是国内仅有的三家白金五星级酒店之一。虽然有些年头了，但是维护的很不错。大堂金', '不愧是国内仅有的三家白金五星级酒店之一。虽然有些年头了，但是维护的很不错。大堂金碧辉煌的，随处可见的兰花。酒店园景也超棒。你能相信在广州城中的酒店能有如此美的园景。4楼还有一个酒店自身的博物馆。酒店的服务也很好，每个工作人员都很专业。尤其是前台帮我们办理入住的viria小姐姐。态度特别好，很专业，还给我们升级了房间。房间比较新，应该是新装修过了。同时酒店的早餐也不错，种类多，味道好。酒店整体还是非常推荐的，尤其适合带老人家体验。', '2023-06-25', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282d4e3c98b0941765fcb', '房间奢华舒适，干净明亮景观好。设施齐全应有尽有，服务快捷周到，响应迅速，行政酒廊的四位小妹妹Echo和Tina活泼开朗，Cathy笑容甜美，中文很棒，Beryle高挑干练，几位小妹妹业务熟悉，对餐厅出品介绍详尽，也贴心地给出酒店度假游玩的建议，非常感谢，非常满意，有机会再去享受花园酒店的白金五星服务', '["https://dimg04.c-ctrip.com/images/0203912000fd3aaxm7FE8_W_350_350_R5_Q70.jpg?proc=autoorient", "https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png", "https://dimg04.c-ctrip.com/images/0232612000fd28bno455D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232712000fd2kt6vBA5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232112000fd2qkfx2BCA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230u12000fd28rq5C49B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236a12000fd38jffF104_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-09-02', '花园大床房', '大床房', '家庭亲子', 150, 5.017279836814924, 0, 0.0, 36, 3.610917912644224, 9, '["整体满意度", "前台服务", "景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向', '未知酒店', '未知地点', '匿名', '房间奢华舒适，干净明亮景观好。设施齐全应有尽有，服务快捷周到，响应迅速，行政酒廊', '房间奢华舒适，干净明亮景观好。设施齐全应有尽有，服务快捷周到，响应迅速，行政酒廊的四位小妹妹Echo和Tina活泼开朗，Cathy笑容甜美，中文很棒，Beryle高挑干练，几位小妹妹业务熟悉，对餐厅出品介绍详尽，也贴心地给出酒店度假游玩的建议，非常感谢，非常满意，有机会再去享受花园酒店的白金五星服务', '2024-09-02', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282d4e3c98b0941765fcc', '酒店很棒！帮忙登记入住的小邓服务很赞????还免费帮升了房间！酒店的服务小姐姐们都很热情贴心，体验感很好！早餐种类很丰富～游泳也很舒服！下次还来！！！推荐！！！????', '["https://dimg04.c-ctrip.com/images/0233o12000eunr67n41A2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d12000euntmpg36A8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232x12000eunsz4l616A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232p12000eunzj9fF138_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232r12000eunyuiuACDD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-21', '花园大床房', '大床房', '情侣出游', 84, 4.442651256490317, 0, 0.0, 20, 3.044522437723423, 8, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '酒店很棒！帮忙登记入住的小邓服务很赞????还免费帮升了房间！酒店的服务小姐姐们', '酒店很棒！帮忙登记入住的小邓服务很赞????还免费帮升了房间！酒店的服务小姐姐们都很热情贴心，体验感很好！早餐种类很丰富～游泳也很舒服！下次还来！！！推荐！！！????', '2024-07-21', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282d4e3c98b0941765fcf', '特别特别满意，酒店绝美，地理位置优越。办理入住的Mancy 真的是人美服务态度好。详细介绍了酒店环境，还提供了旅游交易。在中秋这个美好的日子，酒店贴心的送上了月饼，还有兔子灯。房间干净整洁，没有干扰的声音，床品也非常舒适。住了2晚，在顶楼旋转餐厅和1楼瀑布餐厅都享用了早餐，餐品高级，心情舒适。还贴心安排了远离地铁的房间，真的是丝毫没有影响，在国庆期间，酒店泳池也开放了。很开心的3天2晚，下次还会入住的。再次感谢热情的Mancy哦，大大的赞??', '["https://dimg04.c-ctrip.com/images/0230m12000cbhoeat0438_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234r12000cbhohal51D1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232n12000cbhucb3BD36_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231o12000cbhqhji143E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233m12000cbht4rc9E70_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235m12000cbhnx8qC318_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 223, 5.41164605185504, 0, 0.0, 14, 2.70805020110221, 9, '["整体满意度", "前台服务", "卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况', '未知酒店', '未知地点', '匿名', '特别特别满意，酒店绝美，地理位置优越。办理入住的Mancy 真的是人美服务态度好', '特别特别满意，酒店绝美，地理位置优越。办理入住的Mancy 真的是人美服务态度好。详细介绍了酒店环境，还提供了旅游交易。在中秋这个美好的日子，酒店贴心的送上了月饼，还有兔子灯。房间干净整洁，没有干扰的声音，床品也非常舒适。住了2晚，在顶楼旋转餐厅和1楼瀑布餐厅都享用了早餐，餐品高级，心情舒适。还贴心安排了远离地铁的房间，真的是丝毫没有影响，在国庆期间，酒店泳池也开放了。很开心的3天2晚，下次还会入住的。再次感谢热情的Mancy哦，大大的赞??', '2023-10-03', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282dfe3c98b0941765fd1', '花园酒店性价比非常好，最大亮点是带瀑布的花园，下午坐在瀑布下喝咖啡，逛逛花园全家都很喜欢，三层楼还有酒店的博物馆可以参观，前台的黄先生办理入住的时候非常耐心的介绍了酒店餐饮和服务设施。非常愉快的一次住店经历', '["https://dimg04.c-ctrip.com/images/0235r12000asnk4de09D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232l12000asns42h9017_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236n12000asnr7b6FC90_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y12000asnpttfDFFE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232912000asnlprhD795_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-21', '红棉双床套房', '套房', '家庭亲子', 103, 4.6443908991413725, 0, 0.0, 1, 0.6931471805599453, 9, '["性价比", "整体满意度", "前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '花园酒店性价比非常好，最大亮点是带瀑布的花园，下午坐在瀑布下喝咖啡，逛逛花园全家', '花园酒店性价比非常好，最大亮点是带瀑布的花园，下午坐在瀑布下喝咖啡，逛逛花园全家都很喜欢，三层楼还有酒店的博物馆可以参观，前台的黄先生办理入住的时候非常耐心的介绍了酒店餐饮和服务设施。非常愉快的一次住店经历', '2023-03-21', 5, '性价比');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282dfe3c98b0941765fd9', '酒店环境很棒 前台的Cathy和yomi服务很好 酒店还有个很大的后花园也很漂亮', '["https://dimg04.c-ctrip.com/images/0201w12000as12b6857F9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-03-16', '花园行政双床套房', '套房', '商务出差', 40, 3.713572066704308, 0, 0.0, 5, 1.791759469228055, 6, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '酒店环境很棒 前台的Cathy和yomi服务很好 酒店还有个很大的后花园也很漂亮', '酒店环境很棒 前台的Cathy和yomi服务很好 酒店还有个很大的后花园也很漂亮', '2023-03-16', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282eae3c98b0941765fda', '做飞机来的，附近地铁交通非常方便！
酒店设施卫生环境都很好！服务也很不错，有需求可以直接找大堂的小哥哥小姐姐，会很贴心及时的帮助你 顺便要特意感谢行政酒廊的Carrie小姐姐，服务特别好，态度很热情??，下次有机会还会再来的！
也会推荐朋友们来哟', '["https://dimg04.c-ctrip.com/images/0235f12000aijx2353FC0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236212000aijxbqfF6A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233e12000aijvmj744FB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231b12000aijvtan5DC3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-01-26', '城央绿意大床房', '大床房', '家庭亲子', 123, 4.820281565605037, 0, 0.0, 1, 0.6931471805599453, 8, '["交通便利性", "前台服务", "整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '做飞机来的，附近地铁交通非常方便！', '做飞机来的，附近地铁交通非常方便！
酒店设施卫生环境都很好！服务也很不错，有需求可以直接找大堂的小哥哥小姐姐，会很贴心及时的帮助你 顺便要特意感谢行政酒廊的Carrie小姐姐，服务特别好，态度很热情??，下次有机会还会再来的！
也会推荐朋友们来哟', '2023-01-26', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282eae3c98b0941765fdb', '每次入住花园酒店，都会有意外惊喜[呲牙]。始终是老牌五星酒店，服务十分到位。管家部行政副管家-许诗玮Janice小姐，细节处做到十分到位，有问必答，亲力亲为。酒店的荔湾亭，环境优雅，十足旧时荔枝湾涌，小桥、流水、树荫、小艇。至于食品，一如既往的喜欢。由于有老人家，荔湾亭的梁经理特别的细心、特别的照顾。点心主管李师傅很专业，虚心，细心听取客人对食品意见。', '["https://dimg04.c-ctrip.com/images/0231i12000d2memmaC7F4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235a12000d2mhgcn4D72_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231l12000d2mb7b83962_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232h12000d2mb7ba331A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231n12000d2mh4ldBCC3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236u12000d2mcxw74594_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232f12000d2mbb6846A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-29', '红棉双床套房', '套房', '朋友出游', 177, 5.181783550292085, 0, 0.0, 25, 3.258096538021482, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '每次入住花园酒店，都会有意外惊喜[呲牙]。始终是老牌五星酒店，服务十分到位。管家', '每次入住花园酒店，都会有意外惊喜[呲牙]。始终是老牌五星酒店，服务十分到位。管家部行政副管家-许诗玮Janice小姐，细节处做到十分到位，有问必答，亲力亲为。酒店的荔湾亭，环境优雅，十足旧时荔枝湾涌，小桥、流水、树荫、小艇。至于食品，一如既往的喜欢。由于有老人家，荔湾亭的梁经理特别的细心、特别的照顾。点心主管李师傅很专业，虚心，细心听取客人对食品意见。', '2024-01-29', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282eae3c98b0941765fdd', '住宿体验很好，管家Janice服务也非常棒～是很棒的一次旅程！', '["https://dimg04.c-ctrip.com/images/0233012000e6psfwgDE3D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000e6pl6e0E357_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z12000e6pnwtbDACA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-05-27', '花园大床房', '大床房', '其他', 31, 3.4657359027997265, 0, 0.0, 3, 1.3862943611198906, 4, '["整体满意度", "前台服务"]'::jsonb, '整体满意度', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '住宿体验很好，管家Janice服务也非常棒～是很棒的一次旅程！', '住宿体验很好，管家Janice服务也非常棒～是很棒的一次旅程！', '2024-05-27', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('680282eae3c98b0941765fde', '设施：广州老牌酒店，设施维护的不错，一进大门就能感受到花园酒店的厚重感。房价咖啡机等配备齐全，备品很香，不错。但对于花园酒店来说，早餐的品类少，不太符合酒店的定位。
卫生：卫生做的干净，没有可挑剔的。
环境：环境自然不用说，酒店后花园很舒服，坐在酒廊看外面喷泉瀑布，很是惬意。
服务：重点说说服务吧，留下印象最深的是前台宾客服务的Tony，得知我第一次来，详细地介绍了酒店各项服务，房间进行了升级，很热情。酒廊的服务也很不错，主动热情。
但瀑布餐厅的服务相比之下就差很多，7点报房号进入，没人带位，前台不主动。', '["https://dimg04.c-ctrip.com/images/0232812000bnursm73CAC_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235612000bnuyaad0643_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230f12000bnuy4sr72A1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s12000bnuxt9lBC5C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234312000bnv0g6f9EDE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p12000bnuzl3sCA5E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000bnuw9wr387F_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h12000bnuzqqaA57A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236112000bnuyu0xC856_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-07-15', '城央绿意大床房', '大床房', '独自旅行', 256, 5.54907608489522, 0, 0.0, 11, 2.4849066497880004, 9, '["前台服务", "餐饮设施", "整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度', '未知酒店', '未知地点', '匿名', '设施：广州老牌酒店，设施维护的不错，一进大门就能感受到花园酒店的厚重感。房价咖啡', '设施：广州老牌酒店，设施维护的不错，一进大门就能感受到花园酒店的厚重感。房价咖啡机等配备齐全，备品很香，不错。但对于花园酒店来说，早餐的品类少，不太符合酒店的定位。
卫生：卫生做的干净，没有可挑剔的。
环境：环境自然不用说，酒店后花园很舒服，坐在酒廊看外面喷泉瀑布，很是惬意。
服务：重点说说服务吧，留下印象最深的是前台宾客服务的Tony，得知我第一次来，详细地介绍了酒店各项服务，房间进行了升级，很热情。酒廊的服务也很不错，主动热情。
但瀑布餐厅的服务相比之下就差很多，7点报房号进入，没人带位，前台不主动。', '2023-07-15', 4, '前台服务');
