INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028327e3c98b0941766014', '用住宿券换了两个房间，前台安排到公寓式大套间，内有4套房2大厅，2佰多3佰平方，地方好大，唯公寓式装修是8O，90年代，还包含了夜茶及翌日早餐，酒店位置十分方便在越秀区淘金站，前方有友谊商店及丽柏广场饮食购物，走5分钟有保利时光里大型购物中心等', '["https://dimg04.c-ctrip.com/images/0236i224x8xib5a1y6991_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02313224x8xia377hF434_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230n224x8xiar7sjC991_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233p224x8xi9thy253E6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230l224x8xia377i0536_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c224x8xicev5y3537_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2024-11-14', '花园双床房', '双床房', '家庭亲子', 122, 4.812184355372417, 0, 0.0, 10, 2.3978952727983707, 8, '["周边配套", "交通便利性", "性价比"]'::jsonb, '周边配套', '交通便利性', '性价比', '未知酒店', '未知地点', '匿名', '用住宿券换了两个房间，前台安排到公寓式大套间，内有4套房2大厅，2佰多3佰平方，', '用住宿券换了两个房间，前台安排到公寓式大套间，内有4套房2大厅，2佰多3佰平方，地方好大，唯公寓式装修是8O，90年代，还包含了夜茶及翌日早餐，酒店位置十分方便在越秀区淘金站，前方有友谊商店及丽柏广场饮食购物，走5分钟有保利时光里大型购物中心等', '2024-11-14', 3, '周边配套');
