INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028331e3c98b0941766017', '圣诞节，很热闹，大堂的圣诞小屋还有圣诞点心礼品售卖，早餐可以多种选择，房间很干净，是很广府的文化气息，工作人员都很nice.', '["https://dimg04.c-ctrip.com/images/0236j12000h3z6oga94E3_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230912000h3yr3le5E53_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231s12000h3z7bc59699_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y12000h3z3aziD8B1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235f12000h3zmyse5F44_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-12-08', '红棉大床套房', '套房', '商务出差', 62, 4.143134726391533, 0, 0.0, 5, 1.791759469228055, 7, '["整体满意度", "餐饮设施", "卫生状况"]'::jsonb, '整体满意度', '餐饮设施', '卫生状况', '未知酒店', '未知地点', '匿名', '圣诞节，很热闹，大堂的圣诞小屋还有圣诞点心礼品售卖，早餐可以多种选择，房间很干净', '圣诞节，很热闹，大堂的圣诞小屋还有圣诞点心礼品售卖，早餐可以多种选择，房间很干净，是很广府的文化气息，工作人员都很nice.', '2024-12-08', 5, '整体满意度');
