INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802833ee3c98b0941766020', '服务态度、环境还可以，由于交易会期间，客人比较多，但服务工作人员都比较耐心，尽快给到房间客人，尤其喜欢室外暖水按摩池，小朋友好喜欢。', '["https://dimg04.c-ctrip.com/images/0231l224x8x3j83e85956_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232c224x8x3kzrf66D43_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b224x8x3jwnno403B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-10-23', '城央绿意大床房', '大床房', '家庭亲子', 66, 4.204692619390966, 0, 0.0, 3, 1.3862943611198906, 7, '["前台服务", "公共设施", "整体满意度"]'::jsonb, '前台服务', '公共设施', '整体满意度', '未知酒店', '未知地点', '匿名', '服务态度、环境还可以，由于交易会期间，客人比较多，但服务工作人员都比较耐心，尽快', '服务态度、环境还可以，由于交易会期间，客人比较多，但服务工作人员都比较耐心，尽快给到房间客人，尤其喜欢室外暖水按摩池，小朋友好喜欢。', '2024-10-23', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802833ee3c98b0941766021', '这是我们回国第二次入住花园酒店，我们预订了5天；办理入住的前台玲玲负责接待我们，她的服务态度非常好，解释清晰，非常细心，办理入住手续快捷，安排的房间在13楼房间干净整洁，客房部清洁人员非常勤快，每天准时清洁房间卫生，服务态度也是超好的，总体客房部表现不错
我们在酒店尝试了不同的美食，从桃园馆的早餐，至午餐的荔湾亭还有晚餐的瀑布餐厅的自助餐，最后还有已经二次光顾的「庭」日本餐厅，当然回广州还有点外卖心点评一下餐饮部；早茶的点心中规中矩，不足的地方是虾饺皮较厚，肉质较柴，萝卜糕很好吃
荔湾亭出品；价格跟品质对等，出餐快「因为我们需要赶车去香港转飞机，所以需要40分钟内吃完」部长也快速完成任务，赞一个
瀑布餐厅自助餐；出品满意，食物品种多样，主管Joanna 非常贴心，细致，餐后会细心询问客人的意见与满意度，这是非常难得的c
最后是日本餐厅「庭」；这是我第二次光顾他们，经理与客服人员服务一如既往的5星，食物需要改进的部份是天妇罗，天妇罗的粉浆调的稍浓，所以导致上浆过厚，口感不够松化。
Ps：酒店也贴心的安置了外卖柜在酒店内中国银行的旁边！！如果想喝啤酒，也可以在酒店附设的小卖店购买，我购买了3瓶Asahi辛口啤酒，15元一瓶，「价格合理」。
下次回来会继续入住！', '["https://dimg04.c-ctrip.com/images/0231n224x8vuqalazCAFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231a224x8vuoz7sy05AB_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02321224x8vupo01u6A9A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235n224x8vup17dsF1E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02312224x8vuotdpl8AB4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02317224x8vupnynyE1F2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02361224x8vuq4j937088_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j224x8vuox4qgBF3A_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235s224x8vunytg27B4A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-08-06', '花园双床房', '双床房', '家庭亲子', 536, 6.285998094508865, 0, 0.0, 3, 1.3862943611198906, 9, '["餐饮设施", "前台服务", "客房服务"]'::jsonb, '餐饮设施', '前台服务', '客房服务', '未知酒店', '未知地点', '匿名', '这是我们回国第二次入住花园酒店，我们预订了5天；办理入住的前台玲玲负责接待我们，', '这是我们回国第二次入住花园酒店，我们预订了5天；办理入住的前台玲玲负责接待我们，她的服务态度非常好，解释清晰，非常细心，办理入住手续快捷，安排的房间在13楼房间干净整洁，客房部清洁人员非常勤快，每天准时清洁房间卫生，服务态度也是超好的，总体客房部表现不错
