INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802833ee3c98b0941766026', '酒店位置很好，去那里玩都很方便，进入酒店好有气派，豪华，外面的瀑布好壮观，锦鲤池很漂亮！但对房间的环境觉得一般，洗手间的玻璃门很卡，洗手间和冲凉房的门需要推来推去共用。最不满意是晚上的点心不包茶水，选择的品种少，没青菜、肠粉的选择，如果需要喝茶，需要 20 元一位，如果是白开水就 18 元一位，所以对不包茶水这一点不太满意。但酒店工作人员的服务态度真的非常好！每一位同事都很热情。', '["https://dimg04.c-ctrip.com/images/0232812000eyco2tp0443_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231012000eycoaz4B569_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231o12000eycoaml6F44_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236012000eyco592CFD0_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0230k12000eycocjs1166_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0231112000eycoqwm78DB_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232c12000eycovgj2E0A_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0236b12000eycov2r6F54_R_150_150_R5_Q70_D.png"]'::jsonb, 4.2, 4, '2024-07-31', '花园双床房', '双床房', '家庭亲子', 191, 5.2574953720277815, 0, 0.0, 2, 1.0986122886681098, 8, '["周边配套", "房间设施", "餐饮设施"]'::jsonb, '周边配套', '房间设施', '餐饮设施', '未知酒店', '未知地点', '匿名', '酒店位置很好，去那里玩都很方便，进入酒店好有气派，豪华，外面的瀑布好壮观，锦鲤池', '酒店位置很好，去那里玩都很方便，进入酒店好有气派，豪华，外面的瀑布好壮观，锦鲤池很漂亮！但对房间的环境觉得一般，洗手间的玻璃门很卡，洗手间和冲凉房的门需要推来推去共用。最不满意是晚上的点心不包茶水，选择的品种少，没青菜、肠粉的选择，如果需要喝茶，需要 20 元一位，如果是白开水就 18 元一位，所以对不包茶水这一点不太满意。但酒店工作人员的服务态度真的非常好！每一位同事都很热情。', '2024-07-31', 4, '周边配套');
