INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802833ee3c98b0941766028', '咁岩有事返内地，顺路去广州玩兼同老婆庆生。今次入住花园酒店三晚，地点方便极近淘金地铁站。 酒店大堂金碧辉煌，好有气派，前台同事特意帮我哋升级左套房，间房好大而且卫生。感谢帮我地check in既前台同事niki, 笑容亲切有礼，态度和蔼。老婆生日 酒店有送生日蛋糕。全个入住体验十分满意。下次黎广州都会再考虑花园酒店', '["https://dimg04.c-ctrip.com/images/02331224x8vq6csey7DFD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02359224x8vq6csf0EE8D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233v224x8vq65r6u1F15_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z224x8vq4abye3801_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-25', '花园大床房', '大床房', '情侣出游', 158, 5.068904202220232, 0, 0.0, 9, 2.302585092994046, 8, '["前台服务", "交通便利性", "整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '咁岩有事返内地，顺路去广州玩兼同老婆庆生。今次入住花园酒店三晚，地点方便极近淘金', '咁岩有事返内地，顺路去广州玩兼同老婆庆生。今次入住花园酒店三晚，地点方便极近淘金地铁站。 酒店大堂金碧辉煌，好有气派，前台同事特意帮我哋升级左套房，间房好大而且卫生。感谢帮我地check in既前台同事niki, 笑容亲切有礼，态度和蔼。老婆生日 酒店有送生日蛋糕。全个入住体验十分满意。下次黎广州都会再考虑花园酒店', '2024-07-25', 5, '前台服务');
