INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602a', '酒店位置好，近淘金地铁站位处广州中心点，出行那里都方便，附近有很多美食咖啡店，职员专业有礼，客房干净明亮', '["https://dimg04.c-ctrip.com/images/0234a224x8x9xtoze4273_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235p224x8x9y5lvdC366_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-11-02', '花园大床房', '大床房', '商务出差', 52, 3.970291913552122, 0, 0.0, 77, 4.356708826689592, 7, '["交通便利性", "周边配套", "卫生状况"]'::jsonb, '交通便利性', '周边配套', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店位置好，近淘金地铁站位处广州中心点，出行那里都方便，附近有很多美食咖啡店，职', '酒店位置好，近淘金地铁站位处广州中心点，出行那里都方便，附近有很多美食咖啡店，职员专业有礼，客房干净明亮', '2024-11-02', 5, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602b', '这次订了红棉升级到粤韵，非常宽敞舒适，十分值得推荐。房间装修还很新净，细节安排很好，浴缸超赞，而且住在花园特别有广东风味，不像其他国际品牌，有现代感但没有地方特色。泳池和健身室都不错，不能错过荔湾亭的点心和瀑布餐厅的自助餐。', '["https://dimg04.c-ctrip.com/images/0235w12000eqzb5ys8E2E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235512000eqzatbbCA02_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230412000eqzb8ik4338_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t12000eqzb008845F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-11', '红棉大床套房', '套房', '家庭亲子', 112, 4.727387818712341, 0, 0.0, 5, 1.791759469228055, 9, '["房间设施", "整体满意度", "餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施', '未知酒店', '未知地点', '匿名', '这次订了红棉升级到粤韵，非常宽敞舒适，十分值得推荐。房间装修还很新净，细节安排很', '这次订了红棉升级到粤韵，非常宽敞舒适，十分值得推荐。房间装修还很新净，细节安排很好，浴缸超赞，而且住在花园特别有广东风味，不像其他国际品牌，有现代感但没有地方特色。泳池和健身室都不错，不能错过荔湾亭的点心和瀑布餐厅的自助餐。', '2024-07-11', 5, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602c', '我很喜欢这个地方。它是老式豪华酒店的典范，散发着优雅气息，维护得非常好。房间很漂亮，很有特色，室外场地也很不错。餐厅简直太棒了：Stiller 是我在广州最喜欢的餐厅，铁板烧餐厅很棒，大堂里甚至还有地方可以喝一杯拿铁，还有很棒的糕点可供选择。从红线地铁步行 2 分钟即可到达。', '["https://dimg04.c-ctrip.com/images/0234h12000faep8kaD283_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235o12000faep4g93D96_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0235k12000faep29nDE61_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-08-28', '红棉双床套房', '套房', '商务出差', 138, 4.934473933130692, 0, 0.0, 16, 2.833213344056216, 9, '["餐饮设施", "交通便利性", "整体满意度"]'::jsonb, '餐饮设施', '交通便利性', '整体满意度', '未知酒店', '未知地点', '匿名', '我很喜欢这个地方。它是老式豪华酒店的典范，散发着优雅气息，维护得非常好。房间很漂', '我很喜欢这个地方。它是老式豪华酒店的典范，散发着优雅气息，维护得非常好。房间很漂亮，很有特色，室外场地也很不错。餐厅简直太棒了：Stiller 是我在广州最喜欢的餐厅，铁板烧餐厅很棒，大堂里甚至还有地方可以喝一杯拿铁，还有很棒的糕点可供选择。从红线地铁步行 2 分钟即可到达。', '2024-08-28', 5, '餐饮设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602d', '红棉双床房气派不凡, 楼层提供贴心管家服务. 房间整洁没有吸烟的气味. 经平台订了两个房间, 但前台服务员说要自己通知酒店安排同一楼层, 否则要分开分开两个楼层. 等了两小时极力争取下, 方可安排同一楼层.  这方面Trip.com 极需要反映给酒店知道.', '["https://dimg04.c-ctrip.com/images/0234t12000er0iwh02CB9_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-07-11', '红棉双床套房', '套房', '家庭亲子', 128, 4.859812404361672, 0, 0.0, 5, 1.791759469228055, 7, '["前台服务", "客房服务", "卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况', '未知酒店', '未知地点', '匿名', '红棉双床房气派不凡, 楼层提供贴心管家服务. 房间整洁没有吸烟的气味. 经平台订', '红棉双床房气派不凡, 楼层提供贴心管家服务. 房间整洁没有吸烟的气味. 经平台订了两个房间, 但前台服务员说要自己通知酒店安排同一楼层, 否则要分开分开两个楼层. 等了两小时极力争取下, 方可安排同一楼层.  这方面Trip.com 极需要反映给酒店知道.', '2024-07-11', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602e', '房间大且漂亮，非常洁净。酒店员工友善专业。酒店设施很多，遗憾没享用泳池。以五星酒店计，早餐实有空间作出改善。整体入住体验非常好，会再次入住此酒店。', '["https://dimg04.c-ctrip.com/images/0235d12000f2cex991E06_R_150_150_R5_Q70_D.png", "https://dimg04.c-ctrip.com/images/0232h12000f2cevpnDDEF_R_150_150_R5_Q70_D.png"]'::jsonb, 5.0, 5, '2024-08-09', '红棉大床套房', '套房', '独自旅行', 73, 4.30406509320417, 0, 0.0, 7, 2.079441541679836, 7, '["整体满意度", "房间设施", "卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况', '未知酒店', '未知地点', '匿名', '房间大且漂亮，非常洁净。酒店员工友善专业。酒店设施很多，遗憾没享用泳池。以五星酒', '房间大且漂亮，非常洁净。酒店员工友善专业。酒店设施很多，遗憾没享用泳池。以五星酒店计，早餐实有空间作出改善。整体入住体验非常好，会再次入住此酒店。', '2024-08-09', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b094176602f', '住了一晚，非常愉快。免费升级到 66 型房。', '["https://dimg04.c-ctrip.com/images/02353224x8xe9puh0E6E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-11-08', '花园大床房', '大床房', '商务出差', 22, 3.1354942159291497, 0, 0.0, 22, 3.1354942159291497, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '住了一晚，非常愉快。免费升级到 66 型房。', '住了一晚，非常愉快。免费升级到 66 型房。', '2024-11-08', 4, '整体满意度');
