INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b0941766032', '总体来说，都可以，就是设施有点旧，服务是可以的，免费帮房间升级。前台小哥哥服务好，点赞，最值得看得是酒店的博物馆。', '["https://dimg04.c-ctrip.com/images/02336224x8w3zmtpr6A8E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-29', '花园双床房', '双床房', '家庭亲子', 57, 4.060443010546419, 0, 0.0, 4, 1.6094379124341005, 6, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '总体来说，都可以，就是设施有点旧，服务是可以的，免费帮房间升级。前台小哥哥服务好', '总体来说，都可以，就是设施有点旧，服务是可以的，免费帮房间升级。前台小哥哥服务好，点赞，最值得看得是酒店的博物馆。', '2024-08-29', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028349e3c98b0941766033', '房间布局和设计不太人性化。工作人员很有礼貌，英语熟练', '["https://dimg04.c-ctrip.com/images/0236j224x8x2g6ccz5F33_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02370224x8x2i8pcnA8E4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02343224x8x2hcgyq9FBE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-10-21', '花园大床房', '大床房', '家庭亲子', 26, 3.295836866004329, 0, 0.0, 21, 3.091042453358316, 5, '["房间设施", "前台服务"]'::jsonb, '房间设施', '前台服务', NULL, '未知酒店', '未知地点', '匿名', '房间布局和设计不太人性化。工作人员很有礼貌，英语熟练', '房间布局和设计不太人性化。工作人员很有礼貌，英语熟练', '2024-10-21', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028353e3c98b0941766034', '非常喜欢在这里住了两个星期！工作人员非常友好和乐于助人，清洁工总是那么健谈和有礼貌，每天都会把我的房间打扫得那么干净。我一定会再来这家酒店住，也会推荐给我的家人和朋友！', '["https://dimg04.c-ctrip.com/images/0236812000eszop9fE5C2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0237212000eszmshb167D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230z12000eszogsiBD98_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231212000eszjeh84B22_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236712000eszozf1BA0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-07-17', '花园大床房', '大床房', '商务出差', 84, 4.442651256490317, 0, 0.0, 6, 1.9459101490553128, 8, '["客房服务", "整体满意度", "卫生状况"]'::jsonb, '客房服务', '整体满意度', '卫生状况', '未知酒店', '未知地点', '匿名', '非常喜欢在这里住了两个星期！工作人员非常友好和乐于助人，清洁工总是那么健谈和有礼', '非常喜欢在这里住了两个星期！工作人员非常友好和乐于助人，清洁工总是那么健谈和有礼貌，每天都会把我的房间打扫得那么干净。我一定会再来这家酒店住，也会推荐给我的家人和朋友！', '2024-07-17', 5, '客房服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028353e3c98b0941766035', '本人和父母于2024/06 租住两相连房间 住两日
以下系本人所见所闻
1 浴缸设计独特 位置新颖 但漏水
2 房景若对游客就略微扣分 酒店此处外观需要尽快现代化
3 楼层走?设计很好 和父母拍了多张留念 如果有花香味道就更好
4 重点：房咭住了两天 坏了好多次 希望酒店方不会为其他客户带来不方便 我被安排到其他房间等待维修时 听到此维修人员态度不太好 
5 房间的茶味道确实不太合适 非一般人可以适应
6 图片中的圆镜 接触不好 
本人的祖辈华侨70年代于广州开始生活 眼见国家级酒店兴建 有幸还有气力住两日 百感交集 时代变迁 略低于水准 希望有朝一日重临酒店', '["https://dimg04.c-ctrip.com/images/0230k224x8weq1lsm3366_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02308224x8weph2kj92BE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235y224x8weq0z8m2F55_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233b224x8wepisg7B5C7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231x224x8wepvbtzB3F8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231z224x8weov5ys97D0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g224x8wepintc6015_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02344224x8wep76t2AE5D_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t224x8wepq3daE974_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2024-09-16', '花园大床房', '大床房', '独自旅行', 284, 5.652489180268651, 0, 0.0, 1, 0.6931471805599453, 7, '["房间设施", "前台服务", "整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度', '未知酒店', '未知地点', '匿名', '本人和父母于2024/06 租住两相连房间 住两日', '本人和父母于2024/06 租住两相连房间 住两日
以下系本人所见所闻
1 浴缸设计独特 位置新颖 但漏水
2 房景若对游客就略微扣分 酒店此处外观需要尽快现代化
3 楼层走?设计很好 和父母拍了多张留念 如果有花香味道就更好
4 重点：房咭住了两天 坏了好多次 希望酒店方不会为其他客户带来不方便 我被安排到其他房间等待维修时 听到此维修人员态度不太好 
5 房间的茶味道确实不太合适 非一般人可以适应
6 图片中的圆镜 接触不好 
本人的祖辈华侨70年代于广州开始生活 眼见国家级酒店兴建 有幸还有气力住两日 百感交集 时代变迁 略低于水准 希望有朝一日重临酒店', '2024-09-16', 4, '房间设施');
