INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028353e3c98b094176603a', '房间宽阔，整洁，舒适，用品齐全，工作人员热情款待，由入住开始，有专人招呼，十分体贴，直接带入房间。还介绍洒店内设施，我们入住3天，享用行政礼遇，丰富自助早餐，下午茶，欢乐时光。出品唔错，还品尝二间米其林歺厅，荔湾亭，桃园馆，吃到美味佳肴，下次一定会再来！', '["https://dimg04.c-ctrip.com/images/0235512000dhmf82n5876_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230o12000dhmfb2v42C0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236j12000dhmfl9o1E32_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236c12000dhmg3shCD9C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236e12000dhmfx6448E5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233012000dhmg81q3A4B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230712000dhmg25w0153_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235012000dhmg6q193E0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230q12000dhmf82t765C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-24', '粤韵双床套房', '套房', '独自旅行', 127, 4.852030263919617, 0, 0.0, 1, 0.6931471805599453, 9, '["整体满意度", "餐饮设施", "前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务', '未知酒店', '未知地点', '匿名', '房间宽阔，整洁，舒适，用品齐全，工作人员热情款待，由入住开始，有专人招呼，十分体', '房间宽阔，整洁，舒适，用品齐全，工作人员热情款待，由入住开始，有专人招呼，十分体贴，直接带入房间。还介绍洒店内设施，我们入住3天，享用行政礼遇，丰富自助早餐，下午茶，欢乐时光。出品唔错，还品尝二间米其林歺厅，荔湾亭，桃园馆，吃到美味佳肴，下次一定会再来！', '2024-03-24', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028353e3c98b094176603b', '不愧是老牌的五星酒店，服务和硬件都无可挑剔。适逢广交会，人比较多，早餐也开放了三个餐厅，最起码我就不用等。早上还在我住的楼层电梯口那边准备好?啡，给那些睡过头赶出门的住客提供了贴心服务。这次房间被免费升级了，多了个客厅可以用。房间洗漱用品都很全，连漱口水也有。贵是贵了，但是物有所值。', '["https://dimg04.c-ctrip.com/images/0232312000dozai7b1029_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232k12000doz1q5t5DFA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234n12000dozd3x05C74_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231512000dp0049oE3E2_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232q12000doz8leoFBF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-04-16', '花园大床房', '大床房', '商务出差', 142, 4.962844630259907, 0, 0.0, 123, 4.820281565605037, 9, '["整体满意度", "前台服务", "性价比"]'::jsonb, '整体满意度', '前台服务', '性价比', '未知酒店', '未知地点', '匿名', '不愧是老牌的五星酒店，服务和硬件都无可挑剔。适逢广交会，人比较多，早餐也开放了三', '不愧是老牌的五星酒店，服务和硬件都无可挑剔。适逢广交会，人比较多，早餐也开放了三个餐厅，最起码我就不用等。早上还在我住的楼层电梯口那边准备好?啡，给那些睡过头赶出门的住客提供了贴心服务。这次房间被免费升级了，多了个客厅可以用。房间洗漱用品都很全，连漱口水也有。贵是贵了，但是物有所值。', '2024-04-16', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028353e3c98b094176603c', '酒店环境服务周边商场交通配套都很好，自助早餐款式选择味道也不错，用餐餐厅瀑布环境才是重点。房间洗手盘边位长霉菌需留意。', '["https://dimg04.c-ctrip.com/images/0230h224x8v9m3vu65D1E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02364224x8v9lmw3pF350_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-12', '花园双床房', '双床房', '朋友出游', 59, 4.0943445622221, 0, 0.0, 11, 2.4849066497880004, 7, '["周边配套", "餐饮设施", "卫生状况"]'::jsonb, '周边配套', '餐饮设施', '卫生状况', '未知酒店', '未知地点', '匿名', '酒店环境服务周边商场交通配套都很好，自助早餐款式选择味道也不错，用餐餐厅瀑布环境', '酒店环境服务周边商场交通配套都很好，自助早餐款式选择味道也不错，用餐餐厅瀑布环境才是重点。房间洗手盘边位长霉菌需留意。', '2024-06-12', 4, '周边配套');
