INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802835fe3c98b0941766041', '一间老牌国宾馆，名气大，设施好，近地铁，附近没有什么食肆，酒店内的人造瀑布非常漂亮，拍照位甚多，我们订的套房很舒适，面积大，床上和洗澡用品亦好，设备齐全，唯一就是 check in 取房排队时间较长，等了差不多 45分钟，但大堂又没有什么梳化坐椅给客人休息，这点可以改善一下。', '["https://dimg04.c-ctrip.com/images/0236w224x8ufarajnA67C_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234y224x8ufb1fa70066_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233t224x8ufas1spC950_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02311224x8ufa19pq978B_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236k224x8ufanqw9F859_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k224x8ufb1v1lC3A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-04-05', '红棉大床套房', '套房', '家庭亲子', 138, 4.934473933130692, 0, 0.0, 30, 3.4339872044851463, 8, '["房间设施", "退房/入住效率", "交通便利性"]'::jsonb, '房间设施', '退房/入住效率', '交通便利性', '未知酒店', '未知地点', '匿名', '一间老牌国宾馆，名气大，设施好，近地铁，附近没有什么食肆，酒店内的人造瀑布非常漂', '一间老牌国宾馆，名气大，设施好，近地铁，附近没有什么食肆，酒店内的人造瀑布非常漂亮，拍照位甚多，我们订的套房很舒适，面积大，床上和洗澡用品亦好，设备齐全，唯一就是 check in 取房排队时间较长，等了差不多 45分钟，但大堂又没有什么梳化坐椅给客人休息，这点可以改善一下。', '2024-04-05', 4, '房间设施');
