INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802835fe3c98b0941766043', '老广的No.1
一入门的确被红楼梦的金碧辉煌惊艳到了
迎宾的小姐姐们也人手充配企待客有方
新年的缘故特意订了比较高小小等级的房型
下午三时到达也排了半小时队才能登记
被告知房间未收拾好
问了我们联系电话说是准备好便会打给我们
再问了迎宾的小姐姐
被告知晚上回来肯定有房的
令人好气又好笑
结果到我们晚上10点多回酒店也未收到电话
房间虽然装修过
也算是对得起国内五星酒店的标准的
和天河那边的新五星是无法相比的了
第二天回来，又另一件趣事发生
洗手间和洗手间垃圾桶没有清理
打电话去问为什么没有清理
竟然说我们开了「请勿打扰」
第一我们肯定是开了「请打扫」
第二如果我们开了请勿打扰
那贵酒店收拾了我们的床铺啊，客厅的垃圾桶啊，更换了毛巾啊…那不是前后矛盾？
于是他们们又急急派了人来处理
反正吧
如果会来广州住不同的酒店体验一下
这老广的白金五星是可以试一下的
那种80/90年代的繁花味道还在
如果不是常来广州
又不希望有太傻的服务
那住过去天河的新五星吧', '["https://dimg04.c-ctrip.com/images/0236w224x8u22vi1n3DEE_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02359224x8u22s0ec12A4_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234w224x8u236yolDBB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2024-02-17', '红棉大床套房', '套房', '家庭亲子', 436, 6.07993319509559, 0, 0.0, 5, 1.791759469228055, 9, '["前台服务", "客房服务", "整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度', '未知酒店', '未知地点', '匿名', '老广的No.1', '老广的No.1
