INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802835fe3c98b0941766044', '酒店位置邻近地铁站，非常方便。酒店房间非常整洁，每天除了基本清洁和更换毛巾，更每日提供新的拖鞋，非常贴心。
