INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802835fe3c98b0941766046', '免费升级到新房型，非常好的体验。花园厚重的历史从大门就能感受到是妥妥的广州天花板之一。员工的服务态度也是世界五星级的。宝宝很喜欢门口的大羊羊和钢琴上的小羊。唯一遗憾是周日入住没赶上酒店博物馆，周一刚好不开', '["https://dimg04.c-ctrip.com/images/02338224x8u5btb9iDF0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-01', '红棉大床套房', '套房', '家庭亲子', 102, 4.634728988229636, 0, 0.0, 36, 3.610917912644224, 9, '["整体满意度", "前台服务", "公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施', '未知酒店', '未知地点', '匿名', '免费升级到新房型，非常好的体验。花园厚重的历史从大门就能感受到是妥妥的广州天花板', '免费升级到新房型，非常好的体验。花园厚重的历史从大门就能感受到是妥妥的广州天花板之一。员工的服务态度也是世界五星级的。宝宝很喜欢门口的大羊羊和钢琴上的小羊。唯一遗憾是周日入住没赶上酒店博物馆，周一刚好不开', '2024-03-01', 5, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802835fe3c98b0941766047', '环境好，房间舒服干净', '["https://dimg04.c-ctrip.com/images/0236f224x8v8o8w6jEC7D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-06-10', '花园大床房', '大床房', '家庭亲子', 10, 2.3978952727983707, 0, 0.0, 6, 1.9459101490553128, 4, '["卫生状况", "整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '环境好，房间舒服干净', '环境好，房间舒服干净', '2024-06-10', 5, '卫生状况');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b0941766048', '房间休息好舒服，好干净，是一间拥有好好硬件的酒店，服务员好有礼貌，体验到酒店人材训练有素。
房间不好方面是冲凉时如果是用淋浴会令外面地下湿晒，隔门及淋浴头需要适当地维修。
酒店瀑布餐厅的晚餐自助餐只能说是求精不求多，只是食物都不多，某些受欢迎食物长期没。另外自助早餐真心是失望，食物款式少，而且仲要唔好食。(?晚餐可以试下，早餐就真的不用试)', '["https://dimg04.c-ctrip.com/images/02357224x8tmzhx4s1B80_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232a224x8tmzsb9v8AC7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/02330224x8tmzrvkuF3F6_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0236b224x8tmzws2yA340_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230m224x8tmzws2z66D8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230w224x8tmzrwh8880F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-27', '花园双床房', '双床房', '家庭亲子', 171, 5.147494476813453, 2, 1.0986122886681098, 9, 2.302585092994046, 8, '["房间设施", "卫生状况", "前台服务"]'::jsonb, '房间设施', '卫生状况', '前台服务', '未知酒店', '未知地点', '匿名', '房间休息好舒服，好干净，是一间拥有好好硬件的酒店，服务员好有礼貌，体验到酒店人材', '房间休息好舒服，好干净，是一间拥有好好硬件的酒店，服务员好有礼貌，体验到酒店人材训练有素。
房间不好方面是冲凉时如果是用淋浴会令外面地下湿晒，隔门及淋浴头需要适当地维修。
酒店瀑布餐厅的晚餐自助餐只能说是求精不求多，只是食物都不多，某些受欢迎食物长期没。另外自助早餐真心是失望，食物款式少，而且仲要唔好食。(?晚餐可以试下，早餐就真的不用试)', '2023-12-27', 4, '房间设施');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b0941766049', '这家酒店太棒了', '["https://dimg04.c-ctrip.com/images/0232312000dutltvs2DFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-05-02', '红棉大床套房', '套房', '商务出差', 7, 2.079441541679836, 1, 0.6931471805599453, 10, 2.3978952727983707, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL, '未知酒店', '未知地点', '匿名', '这家酒店太棒了', '这家酒店太棒了', '2024-05-02', 4, '整体满意度');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b094176604a', '一间非常之好嘅酒店、酒店花园非常之优美、服务到位员工非常有礼貌…. 重有惊喜因入住其间是我本人生日、酒店送了一个生日蛋糕??！
为一不满意地方是瀑布餐厅的自助晚餐…食物种类小，选择不多质素非常一般、而且收费和食物质素不成正比！￥300多人民一位食家常小菜自助晚餐有点过份??', '["https://dimg04.c-ctrip.com/images/0233n2234cnp519yoF6BD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232j2234cnp51hogB426_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230k2234cnp51pe84145_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g2215ggyswmi8A36E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023042224wkbyzldsD1F9_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0230t2215ggysx1xtA577_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023352215ggysx9nk6448_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234v2224wkbz08j4DCDF_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023602234cnp537eo9E34_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-25', '花园双床房', '双床房', '家庭亲子', 137, 4.927253685157205, 0, 0.0, 3, 1.3862943611198906, 7, '["餐饮设施", "整体满意度", "前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务', '未知酒店', '未知地点', '匿名', '一间非常之好嘅酒店、酒店花园非常之优美、服务到位员工非常有礼貌…. 重有惊喜因入', '一间非常之好嘅酒店、酒店花园非常之优美、服务到位员工非常有礼貌…. 重有惊喜因入住其间是我本人生日、酒店送了一个生日蛋糕??！
为一不满意地方是瀑布餐厅的自助晚餐…食物种类小，选择不多质素非常一般、而且收费和食物质素不成正比！￥300多人民一位食家常小菜自助晚餐有点过份??', '2023-09-25', 4, '餐饮设施');
