INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b094176604c', '酒店就在地铁站旁边，出行逛街都很方便，办理入住还有送鲜花??，心情一下美好了，另外内部设计设计很好看，就算在酒店里逛逛都能发现新亮点。房间里总体舒适度也够，只因酒店附近有工程在修建，早上8点到晚上10点在室内还是有点声音，就这一点会比较尴尬。入住的话，可以跟前台工作人员咨询一下！', '["https://dimg04.c-ctrip.com/images/023202224x3r1h8zlCA6E_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232g2224x3r1h8zo4B42_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023692234d747k7v4DE67_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-11-13', '花园双床房', '双床房', '朋友出游', 140, 4.948759890378168, 0, 0.0, 5, 1.791759469228055, 8, '["交通便利性", "前台服务", "安静程度"]'::jsonb, '交通便利性', '前台服务', '安静程度', '未知酒店', '未知地点', '匿名', '酒店就在地铁站旁边，出行逛街都很方便，办理入住还有送鲜花??，心情一下美好了，另', '酒店就在地铁站旁边，出行逛街都很方便，办理入住还有送鲜花??，心情一下美好了，另外内部设计设计很好看，就算在酒店里逛逛都能发现新亮点。房间里总体舒适度也够，只因酒店附近有工程在修建，早上8点到晚上10点在室内还是有点声音，就这一点会比较尴尬。入住的话，可以跟前台工作人员咨询一下！', '2023-11-13', 5, '交通便利性');
