INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b094176604e', '服务周到，热情欢迎，非常好的体验', '["https://dimg04.c-ctrip.com/images/0231r224x8uczrphg98D4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-03-29', '城央绿意双床房', '双床房', '家庭亲子', 16, 2.833213344056216, 0, 0.0, 3, 1.3862943611198906, 3, '["前台服务", "整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL, '未知酒店', '未知地点', '匿名', '服务周到，热情欢迎，非常好的体验', '服务周到，热情欢迎，非常好的体验', '2024-03-29', 5, '前台服务');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b094176604f', '酒店房间明显陈旧，希望有机会可以翻新,但地理位置非常好，一出门就有地铁站交通方便,餐厅服务人员很有礼貌，服务周到,桃园厅，食品质量很好，不愧为米之莲餐厅??', '["https://dimg04.c-ctrip.com/images/0230e2215ha1ddahsEA40_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235e2224xdejg1nk9B17_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234d2224xdejg1nn9185_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023562224xdejg1nm5DBD_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233d2224xdejg1nl5DB7_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023282215ha1ddahvA6D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.0, 4, '2023-12-07', '花园大床房', '大床房', '情侣出游', 78, 4.3694478524670215, 0, 0.0, 3, 1.3862943611198906, 7, '["交通便利性", "餐饮设施", "房间设施"]'::jsonb, '交通便利性', '餐饮设施', '房间设施', '未知酒店', '未知地点', '匿名', '酒店房间明显陈旧，希望有机会可以翻新,但地理位置非常好，一出门就有地铁站交通方便', '酒店房间明显陈旧，希望有机会可以翻新,但地理位置非常好，一出门就有地铁站交通方便,餐厅服务人员很有礼貌，服务周到,桃园厅，食品质量很好，不愧为米之莲餐厅??', '2023-12-07', 4, '交通便利性');
INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('6802836ae3c98b0941766050', '解锁中国改革开放的两间标志性的酒店——广州花园酒店。完全没法想像是一家38年的酒店，酒店房好新好舒服，东西一尘不染，大大的好评。', '["https://dimg04.c-ctrip.com/images/0233u224x8tsukd5c9797_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234o224x8tsus81gC424_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233o224x8tsustwa6E8C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2024-01-19', '红棉大床套房', '套房', '情侣出游', 64, 4.174387269895637, 0, 0.0, 94, 4.553876891600541, 6, '["整体满意度", "卫生状况", "房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施', '未知酒店', '未知地点', '匿名', '解锁中国改革开放的两间标志性的酒店——广州花园酒店。完全没法想像是一家38年的酒', '解锁中国改革开放的两间标志性的酒店——广州花园酒店。完全没法想像是一家38年的酒店，酒店房好新好舒服，东西一尘不染，大大的好评。', '2024-01-19', 5, '整体满意度');
