INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028374e3c98b0941766052', '虽然对于地下停车场跟酒店本身没有连通有点不满意，但考虑到酒店的历史，还能安慰一下自己。
直到Check in时，遇到非常友善亲切的Gillian，才让我发现，原来这是一间以人为本的酒店。也正式开启了愉快的一天。
因为老人家比较晚到，也很感谢她能帮我解决很多小问题，很多我还没设想到的，都想到了，非常棒！鲜花也让太座和女鹅非常惊喜！
在房间走道遇到任何的工作人员尽管他/她正在忙，也会友善的问候一句您好。
博物馆也是详细记载了酒店的历史，非常值得一观。
结束疲劳的一天，回到房间也被点心吓一跳，真的很轻易的俘虏了女鹅的小心心。
其实住遍了国际五星难免对于服务这点是特别有感，但花园酒店，有让我觉得，一点都不输。', '["https://dimg04.c-ctrip.com/images/0232y12000c6fm5n03800_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231012000c6ffyqa02EA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0235g12000c6fp8bw5DD0_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0231712000c6fchhgCDCF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5.0, 5, '2023-09-18', '花园双床房', '双床房', '家庭亲子', 305, 5.723585101952381, 0, 0.0, 38, 3.6635616461296463, 9, '["前台服务", "整体满意度", "客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务', '未知酒店', '未知地点', '匿名', '虽然对于地下停车场跟酒店本身没有连通有点不满意，但考虑到酒店的历史，还能安慰一下', '虽然对于地下停车场跟酒店本身没有连通有点不满意，但考虑到酒店的历史，还能安慰一下自己。
直到Check in时，遇到非常友善亲切的Gillian，才让我发现，原来这是一间以人为本的酒店。也正式开启了愉快的一天。
因为老人家比较晚到，也很感谢她能帮我解决很多小问题，很多我还没设想到的，都想到了，非常棒！鲜花也让太座和女鹅非常惊喜！
在房间走道遇到任何的工作人员尽管他/她正在忙，也会友善的问候一句您好。
博物馆也是详细记载了酒店的历史，非常值得一观。
结束疲劳的一天，回到房间也被点心吓一跳，真的很轻易的俘虏了女鹅的小心心。
其实住遍了国际五星难免对于服务这点是特别有感，但花园酒店，有让我觉得，一点都不输。', '2023-09-18', 5, '前台服务');
