INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, log_comment_len, useful_count, log_useful_count, review_count, log_review_count, quality_score, categories, category1, category2, category3, hotel_name, location, reviewer_name, review_title, review_text, review_date, rating, category) VALUES ('68028374e3c98b0941766059', '花园酒店好唔掂！无下次！网上说她好的人绝对是日行一善。酒店大堂气势磅礴，叻得下人。但上到去房间，**一样，装修和设施保持在30年前水平，一点也没有改变。图1，大厦外墙石屎剥落。图2，浴帘霉菌茁壮。图3，墙纸磨到花碌碌。其他图可见，容容烂烂的一间"五星酒店"。一般来说，每年七八月乃旅游旺季，修缉泳池要等冬天才弄，这是常识吧？花园酒店实在烂得要紧，泳池等不及冬天，现在已经停用了。其陈旧程度可见一斑。', '["https://dimg04.c-ctrip.com/images/0231m2224w4k2a2shCEF1_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0234p2215g16w7jch3ED5_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0233h2234c7x8d1o1F356_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023012224w4k2a2si82C8_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/0232w2234c7x8d1o09EDA_R_150_150_R5_Q70_D.jpg", "https://dimg04.c-ctrip.com/images/023312215g16w7jciB87D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.0, 3, '2023-08-16', '红棉双床套房', '套房', '家庭亲子', 199, 5.298317366548036, 1, 0.6931471805599453, 6, 1.9459101490553128, 9, '["房间设施", "公共设施", "卫生状况"]'::jsonb, '房间设施', '公共设施', '卫生状况', '未知酒店', '未知地点', '匿名', '花园酒店好唔掂！无下次！网上说她好的人绝对是日行一善。酒店大堂气势磅礴，叻得下人', '花园酒店好唔掂！无下次！网上说她好的人绝对是日行一善。酒店大堂气势磅礴，叻得下人。但上到去房间，**一样，装修和设施保持在30年前水平，一点也没有改变。图1，大厦外墙石屎剥落。图2，浴帘霉菌茁壮。图3，墙纸磨到花碌碌。其他图可见，容容烂烂的一间"五星酒店"。一般来说，每年七八月乃旅游旺季，修缉泳池要等冬天才弄，这是常识吧？花园酒店实在烂得要紧，泳池等不及冬天，现在已经停用了。其陈旧程度可见一斑。', '2023-08-16', 3, '房间设施');
